-- Aliolo Documentation Translations
-- Generated for 34 languages

INSERT INTO ui_translations (lang, key, value) VALUES
  ('en', 'doc_welcome_title', 'Welcome to Aliolo'),
  ('en', 'doc_welcome_desc', 'Aliolo is a visual learning platform designed to help you master subjects through flashcards and interactive testing.'),
  ('en', 'doc_pillars_title', 'The 8 Core Pillars'),
  ('en', 'doc_pillars_desc', 'All content in Aliolo is organized into 8 foundational pillars: Academic & Professional, World, Nature, Health, Humanities, Leisure, Engineering, and Other. These categories provide a structured framework for all subjects across the platform.'),
  ('en', 'doc_leaderboard_title', 'Global Leaderboard'),
  ('en', 'doc_leaderboard_desc', 'Compete with learners worldwide! Earn XP by completing card sessions and climb the ranks. Your position is updated in real-time as you master new subjects.'),
  ('en', 'doc_friends_title', 'Friends & Invitations'),
  ('en', 'doc_friends_desc', 'Learning is better together! Invite friends to Aliolo through your profile. You can track each other''s progress and stay motivated by seeing who maintains the longest streak.'),
  ('en', 'doc_streaks_title', 'Streak System'),
  ('en', 'doc_streaks_desc', 'Consistency is key! Complete your daily goal every day to build your streak. Don''t miss a day, or the streak will reset.'),
  ('en', 'doc_goals_title', 'Daily Goals'),
  ('en', 'doc_goals_desc', 'Set your daily card completion target in the settings. Changes to your goal take effect starting the next day.'),
  ('en', 'doc_public_title', 'Public vs Private'),
  ('en', 'doc_public_desc', 'Subjects can be private (visible only to you) or public. Public content is shared with the entire Aliolo community, allowing everyone to discover and learn from your creations.'),
  ('en', 'doc_sync_title', 'Cloud Sync'),
  ('en', 'doc_sync_desc', 'Your progress is automatically synced to the cloud. You can switch between web and desktop versions without losing your streak.'),
  ('en', 'doc_feedback_title', 'Feedback System'),
  ('en', 'doc_feedback_desc', 'Help us improve! Use the feedback icon (Icons.feedback) on any Subject or Folder to report issues. You can also send general app feedback through the Support section.'),
  ('en', 'doc_lang_title', 'Learning Language'),
  ('en', 'doc_lang_desc', 'Always select your preferred learning language in the top menu before selecting a subject. This ensures the correct audio and translations are loaded.'),
  ('en', 'doc_filters_title', 'Search & Filters'),
  ('en', 'doc_filters_desc', 'Quickly find content using the search bar. You can filter by Age Group (Early to Advanced) or narrow your view to specific Collections and Folders.'),
  ('en', 'doc_flashcards_title', 'Visual Flashcards'),
  ('en', 'doc_flashcards_desc', 'Each subject contains a set of cards. While images and audio are supported, they are optional—content can be purely textual or dynamically generated.'),
  ('en', 'doc_study_modes_title', 'Adaptive Study Modes'),
  ('en', 'doc_study_modes_desc', 'Aliolo supports various testing modes based on your content: Image-to-Text, Audio-to-Image, and Text-to-Audio. This multi-sensory approach ensures you master subjects from every angle.'),
  ('en', 'doc_testing_title', 'Interactive Testing'),
  ('en', 'doc_testing_desc', 'Challenge yourself with multiple-choice questions (MCQ). The app will automatically advance as you answer, helping you learn faster.'),
  ('en', 'doc_autoplay_title', 'Auto-Play Learning'),
  ('en', 'doc_autoplay_desc', 'The app can automatically advance to the next card after you answer. Correct answers wait 1s, while incorrect ones wait 2s to let you review.'),
  ('en', 'doc_math_title', 'Mathematical Subjects'),
  ('en', 'doc_math_desc', 'Mathematical subjects use specialized engines to generate card visualizations in real-time. These subjects feature unique learning and testing modes tailored to specific mathematical concepts, ensuring a more effective practice environment.'),
  ('en', 'doc_organization_title', 'Organizing Content'),
  ('en', 'doc_organization_desc', 'Use Folders to group related Subjects together. You can also create Collections to organize Subjects into curated paths.'),
  ('en', 'doc_creation_title', 'Creating Subjects & Cards'),
  ('en', 'doc_creation_desc', 'Create your own Subjects and add visual Flashcards. Each card supports an image and an optional audio file for pronunciation.'),
  ('en', 'doc_collections_purpose_title', 'The Purpose of Collections'),
  ('en', 'doc_collections_purpose_desc', 'Collections are curated paths that group Subjects together. When you start a session from a Collection, the system mixes cards from all included subjects to provide a randomized, comprehensive test.'),
  ('en', 'doc_card_scope_title', 'Where Cards Live'),
  ('en', 'doc_card_scope_desc', 'Cards are the building blocks of learning and always belong to a specific Subject. While you can organize Subjects into Folders or Collections, cards themselves must be created within a Subject.'),
  ('en', 'doc_localization_ui_title', 'Adding Translations'),
  ('en', 'doc_localization_ui_desc', 'To add localized data, simply tap the language code icon (e.g., EN, ES, FR) in the editor header. This allows you to provide specific names, descriptions, and card content for each supported language. The "Global" tab serves as the primary fallback if no specific translation is provided.'),
  ('en', 'doc_localization_details_title', 'How Localization Works'),
  ('en', 'doc_localization_details_desc', 'The "Global" language is your primary fallback—it can be any language you choose. If you provide specific translations (like English or Spanish), they will override the Global data only when a user selects that specific UI language.'),
  ('en', 'doc_json_title', 'JSON Localization'),
  ('en', 'doc_json_desc', 'Advanced creators can use JSON data to provide localized names and descriptions, making subjects accessible across all supported languages.'),
  ('en', 'doc_media_title', 'Media Upload Limits'),
  ('en', 'doc_media_desc', 'To ensure fast sync, keep images under 5MB and audio files under 10MB.'),

  ('id', 'doc_welcome_title', 'Selamat datang di Aliolo'),
  ('id', 'doc_welcome_desc', 'Aliolo adalah platform pembelajaran visual yang dirancang untuk membantu Anda menguasai subjek melalui flashcard dan pengujian interaktif.'),
  ('id', 'doc_pillars_title', '8 Pilar Utama'),
  ('id', 'doc_pillars_desc', 'Semua konten di Aliolo diatur ke dalam 8 pilar dasar: Akademik & Profesional, Dunia, Alam, Tubuh Manusia, Humaniora, Waktu Luang, Teknik, dan Lainnya. Kategori ini menyediakan kerangka kerja terstruktur untuk semua subjek di seluruh platform.'),
  ('id', 'doc_leaderboard_title', 'Papan Peringkat Global'),
  ('id', 'doc_leaderboard_desc', 'Bersainglah dengan pelajar di seluruh dunia! Dapatkan XP dengan menyelesaikan sesi kartu dan naikkan peringkat Anda. Posisi Anda diperbarui secara real-time saat Anda menguasai subjek baru.'),
  ('id', 'doc_friends_title', 'Teman & Undangan'),
  ('id', 'doc_friends_desc', 'Belajar lebih baik bersama-sama! Undang teman ke Aliolo melalui profil Anda. Anda dapat melacak kemajuan satu sama lain dan tetap termotivasi dengan melihat siapa yang mempertahankan streak terpanjang.'),
  ('id', 'doc_streaks_title', 'Sistem Streak'),
  ('id', 'doc_streaks_desc', 'Konsistensi adalah kunci! Selesaikan target harian Anda setiap hari untuk membangun streak Anda. Jangan lewatkan satu hari pun, atau streak akan diatur ulang.'),
  ('id', 'doc_goals_title', 'Target Harian'),
  ('id', 'doc_goals_desc', 'Atur target penyelesaian kartu harian Anda di pengaturan. Perubahan pada target Anda mulai berlaku besok.'),
  ('id', 'doc_public_title', 'Publik vs Privat'),
  ('id', 'doc_public_desc', 'Subjek dapat bersifat privat (hanya terlihat oleh Anda) atau publik. Konten publik dibagikan kepada seluruh komunitas Aliolo, memungkinkan semua orang untuk menemukan dan belajar dari kreasi Anda.'),
  ('id', 'doc_sync_title', 'Sinkronisasi Cloud'),
  ('id', 'doc_sync_desc', 'Kemajuan Anda secara otomatis disinkronkan ke cloud. Anda dapat beralih antara versi web dan desktop tanpa kehilangan streak Anda.'),
  ('id', 'doc_feedback_title', 'Sistem Umpan Balik'),
  ('id', 'doc_feedback_desc', 'Bantu kami meningkatkan! Gunakan ikon umpan balik (Icons.feedback) pada Subjek atau Folder apa pun untuk melaporkan masalah. Anda juga dapat mengirim umpan balik aplikasi umum melalui bagian Dukungan.'),
  ('id', 'doc_lang_title', 'Bahasa Pembelajaran'),
  ('id', 'doc_lang_desc', 'Selalu pilih bahasa pembelajaran pilihan Anda di menu atas sebelum memilih subjek. Ini memastikan audio dan terjemahan yang benar dimuat.'),
  ('id', 'doc_filters_title', 'Pencarian & Filter'),
  ('id', 'doc_filters_desc', 'Temukan konten dengan cepat menggunakan bilah pencarian. Anda dapat memfilter berdasarkan Kelompok Usia (Dini hingga Lanjutan) atau mempersempit tampilan ke Koleksi dan Folder tertentu.'),
  ('id', 'doc_flashcards_title', 'Flashcard Visual'),
  ('id', 'doc_flashcards_desc', 'Setiap subjek berisi sekumpulan kartu. Meskipun gambar dan audio didukung, keduanya opsional—konten dapat murni tekstual atau dihasilkan secara dinamis.'),
  ('id', 'doc_study_modes_title', 'Mode Belajar Adaptif'),
  ('id', 'doc_study_modes_desc', 'Aliolo mendukung berbagai mode pengujian berdasarkan konten Anda: Gambar-ke-Teks, Audio-ke-Gambar, dan Teks-ke-Audio. Pendekatan multi-sensorik ini memastikan Anda menguasai subjek dari setiap sudut.'),
  ('id', 'doc_testing_title', 'Pengujian Interaktif'),
  ('id', 'doc_testing_desc', 'Tantang diri Anda dengan pertanyaan pilihan ganda (MCQ). Aplikasi akan maju secara otomatis saat Anda menjawab, membantu Anda belajar lebih cepat.'),
  ('id', 'doc_autoplay_title', 'Pembelajaran Putar Otomatis'),
  ('id', 'doc_autoplay_desc', 'Aplikasi dapat maju secara otomatis ke kartu berikutnya setelah Anda menjawab. Jawaban yang benar menunggu 1 detik, sedangkan jawaban yang salah menunggu 2 detik untuk memungkinkan Anda meninjau.'),
  ('id', 'doc_math_title', 'Subjek Matematika'),
  ('id', 'doc_math_desc', 'Subjek matematika menggunakan mesin khusus untuk menghasilkan visualisasi kartu secara real-time. Subjek-subjek ini menampilkan mode pembelajaran dan pengujian unik yang disesuaikan dengan konsep matematika tertentu, memastikan lingkungan latihan yang lebih efektif.'),
  ('id', 'doc_organization_title', 'Mengatur Konten'),
  ('id', 'doc_organization_desc', 'Gunakan Folder untuk mengelompokkan Subjek terkait secara bersamaan. Anda juga dapat membuat Koleksi untuk mengatur Subjek ke dalam jalur yang dikurasi.'),
  ('id', 'doc_creation_title', 'Membuat Subjek & Kartu'),
  ('id', 'doc_creation_desc', 'Buat Subjek Anda sendiri dan tambahkan Flashcard visual. Setiap kartu mendukung gambar dan file audio opsional untuk pengucapan.'),
  ('id', 'doc_collections_purpose_title', 'Tujuan Koleksi'),
  ('id', 'doc_collections_purpose_desc', 'Koleksi adalah jalur yang dikurasi yang mengelompokkan Subjek secara bersamaan. Saat Anda memulai sesi dari Koleksi, sistem mencampur kartu dari semua subjek yang disertakan untuk memberikan tes komprehensif yang diacak.'),
  ('id', 'doc_card_scope_title', 'Tempat Kartu Berada'),
  ('id', 'doc_card_scope_desc', 'Kartu adalah blok bangunan pembelajaran dan selalu menjadi milik Subjek tertentu. Meskipun Anda dapat mengatur Subjek ke dalam Folder atau Koleksi, kartu itu sendiri harus dibuat di dalam Subjek.'),
  ('id', 'doc_localization_ui_title', 'Menambahkan Terjemahan'),
  ('id', 'doc_localization_ui_desc', 'Untuk menambahkan data terlokalisasi, cukup ketuk ikon kode bahasa (misalnya, EN, ES, FR) di header editor. Ini memungkinkan Anda untuk memberikan nama, deskripsi, dan konten kartu khusus untuk setiap bahasa yang didukung. Tab "Global" berfungsi sebagai fallback utama jika tidak ada terjemahan khusus yang disediakan.'),
  ('id', 'doc_localization_details_title', 'Cara Kerja Lokalisasi'),
  ('id', 'doc_localization_details_desc', 'Bahasa "Global" adalah fallback utama Anda—bisa bahasa apa pun yang Anda pilih. Jika Anda memberikan terjemahan khusus (seperti bahasa Inggris atau Spanyol), terjemahan tersebut akan menimpa data Global hanya ketika pengguna memilih bahasa UI khusus tersebut.'),
  ('id', 'doc_json_title', 'Lokalisasi JSON'),
  ('id', 'doc_json_desc', 'Kreator tingkat lanjut dapat menggunakan data JSON untuk memberikan nama dan deskripsi terlokalisasi, membuat subjek dapat diakses di semua bahasa yang didukung.'),
  ('id', 'doc_media_title', 'Batas Unggahan Media'),
  ('id', 'doc_media_desc', 'Untuk memastikan sinkronisasi cepat, jaga agar gambar di bawah 5MB dan file audio di bawah 10MB.'),

  ('bg', 'doc_welcome_title', 'Добре дошли в Aliolo'),
  ('bg', 'doc_welcome_desc', 'Aliolo е платформа за визуално обучение, създадена да ви помогне да овладеете предмети чрез флаш карти и интерактивно тестване.'),
  ('bg', 'doc_pillars_title', '8-те основни стълба'),
  ('bg', 'doc_pillars_desc', 'Цялото съдържание в Aliolo е организирано в 8 фундаментални стълба: Академични и професионални, Свят, Природа, Човешко тяло, Хуманитарни науки, Свободно време, Инженерство и Други. Тези категории предоставят структурирана рамка за всички предмети в платформата.'),
  ('bg', 'doc_leaderboard_title', 'Глобална класация'),
  ('bg', 'doc_leaderboard_desc', 'Състезавайте се с учащи от целия свят! Печелете XP чрез завършване на сесии с карти и се изкачвайте в ранговете. Вашата позиция се актуализира в реално време, докато усвоявате нови предмети.'),
  ('bg', 'doc_friends_title', 'Приятели и покани'),
  ('bg', 'doc_friends_desc', 'Ученето е по-добро заедно! Поканете приятели в Aliolo чрез вашия профил. Можете да проследявате напредъка си един на друг и да останете мотивирани, като виждате кой поддържа най-дългата серия.'),
  ('bg', 'doc_streaks_title', 'Система от серии (Streaks)'),
  ('bg', 'doc_streaks_desc', 'Постоянството е ключово! Изпълнявайте ежедневната си цел всеки ден, за да изградите своята серия. Не пропускайте нито един ден, иначе серията ще се нулира.'),
  ('bg', 'doc_goals_title', 'Ежедневни цели'),
  ('bg', 'doc_goals_desc', 'Задайте вашата ежедневна цел за завършване на карти в настройките. Промените в целта ви влизат в сила от следващия ден.'),
  ('bg', 'doc_public_title', 'Публични срещу частни'),
  ('bg', 'doc_public_desc', 'Предметите могат да бъдат частни (видими само за вас) или публични. Публичното съдържание се споделя с цялата общност на Aliolo, което позволява на всеки да открива и да се учи от вашите творения.'),
  ('bg', 'doc_sync_title', 'Облачна синхронизация'),
  ('bg', 'doc_sync_desc', 'Вашият напредък автоматично се синхронизира с облака. Можете да превключвате между уеб и десктоп версии, без да губите серията си.'),
  ('bg', 'doc_feedback_title', 'Система за обратна връзка'),
  ('bg', 'doc_feedback_desc', 'Помогнете ни да се подобрим! Използвайте иконата за обратна връзка (Icons.feedback) на всеки предмет или папка, за да съобщите за проблеми. Можете също да изпратите обща обратна връзка за приложението чрез секцията за поддръжка.'),
  ('bg', 'doc_lang_title', 'Език на обучение'),
  ('bg', 'doc_lang_desc', 'Винаги избирайте предпочитания от вас език за обучение в горното меню, преди да изберете предмет. Това гарантира, че се зареждат правилните аудио и преводи.'),
  ('bg', 'doc_filters_title', 'Търсене и филтри'),
  ('bg', 'doc_filters_desc', 'Намерете съдържание бързо с помощта на лентата за търсене. Можете да филтрирате по възрастова група (от ранна до напреднала) или да стесните изгледа си до конкретни колекции и папки.'),
  ('bg', 'doc_flashcards_title', 'Визуални флаш карти'),
  ('bg', 'doc_flashcards_desc', 'Всеки предмет съдържа набор от карти. Въпреки че се поддържат изображения и аудио, те не са задължителни – съдържанието може да бъде чисто текстово или динамично генерирано.'),
  ('bg', 'doc_study_modes_title', 'Адаптивни режими на обучение'),
  ('bg', 'doc_study_modes_desc', 'Aliolo поддържа различни режими на тестване въз основа на вашето съдържание: Изображение към текст, Аудио към изображение и Текст към аудио. Този мултисензорен подход гарантира, че усвоявате предметите от всеки ъгъл.'),
  ('bg', 'doc_testing_title', 'Инрактивно тестване'),
  ('bg', 'doc_testing_desc', 'Предизвикайте себе си с въпроси с избор на отговор (MCQ). Приложението автоматично ще продължи напред, докато отговаряте, помагайки ви да учите по-бързо.'),
  ('bg', 'doc_autoplay_title', 'Обучение с автоматично възпроизвеждане'),
  ('bg', 'doc_autoplay_desc', 'Приложението може автоматично да премине към следващата карта, след като отговорите. Правилните отговори изчакват 1 сек., докато грешните изчакват 2 сек., за да ви позволят да прегледате.'),
  ('bg', 'doc_math_title', 'Математически предмети'),
  ('bg', 'doc_math_desc', 'Математическите предмети използват специализирани машини за генериране на визуализации на карти в реално време. Тези предмети включват уникални режими на обучение и тестване, съобразени с конкретни математически концепции, осигуряващи по-ефективна среда за практикуване.'),
  ('bg', 'doc_organization_title', 'Организиране на съдържанието'),
  ('bg', 'doc_organization_desc', 'Използвайте папки, за да групирате свързани предмети заедно. Можете също да създавате колекции, за да организирате предмети в курирани пътеки.'),
  ('bg', 'doc_creation_title', 'Създаване на предмети и карти'),
  ('bg', 'doc_creation_desc', 'Създайте свои собствени предмети и добавете визуални флаш карти. Всяка карта поддържа изображение и незадължителен аудио файл за произношение.'),
  ('bg', 'doc_collections_purpose_title', 'Целта на колекциите'),
  ('bg', 'doc_collections_purpose_desc', 'Колекциите са курирани пътеки, които групират предмети заедно. Когато започнете сесия от колекция, системата смесва карти от всички включени предмети, за да осигури рандомизиран, всеобхватен тест.'),
  ('bg', 'doc_card_scope_title', 'Къде живеят картите'),
  ('bg', 'doc_card_scope_desc', 'Картите са градивните елементи на обучението и винаги принадлежат към конкретен предмет. Въпреки че можете да организирате предмети в папки или колекции, самите карти трябва да бъдат създадени в рамките на предмет.'),
  ('bg', 'doc_localization_ui_title', 'Добавяне на преводи'),
  ('bg', 'doc_localization_ui_desc', 'За да добавите локализирани данни, просто докоснете иконата на езиковия код (напр. EN, ES, FR) в заглавката на редактора. Това ви позволява да предоставите конкретни имена, описания и съдържание на карти за всеки поддържан език. Разделът "Глобален" служи като основен резервен вариант, ако не е предоставен конкретен превод.'),
  ('bg', 'doc_localization_details_title', 'Как работи локализацията'),
  ('bg', 'doc_localization_details_desc', 'Езикът "Глобален" е вашият основен резервен вариант – той може да бъде всеки език, който изберете. Ако предоставите конкретни преводи (като английски или испански), те ще заменят глобалните данни само когато потребителят избере този конкретен език на потребителския интерфейс.'),
  ('bg', 'doc_json_title', 'JSON локализация'),
  ('bg', 'doc_json_desc', 'Напредналите създатели могат да използват JSON данни, за да предоставят локализирани имена и описания, правейки предметите достъпни на всички поддържани езици.'),
  ('bg', 'doc_media_title', 'Ограничения за качване на медия'),
  ('bg', 'doc_media_desc', 'За да осигурите бърза синхронизация, поддържайте изображенията под 5MB, а аудио файловете под 10MB.'),

  ('cs', 'doc_welcome_title', 'Vítejte v Aliolo'),
  ('cs', 'doc_welcome_desc', 'Aliolo je platforma pro vizuální učení navržená tak, aby vám pomohla ovládnout předměty prostřednictvím kartiček a interaktivního testování.'),
  ('cs', 'doc_pillars_title', '8 hlavních pilířů'),
  ('cs', 'doc_pillars_desc', 'Veškerý obsah v Aliolo je rozdělen do 8 základních pilířů: Akademické a profesionální, Svět, Příroda, Lidské tělo, Humanitní vědy, Volný čas, Inženýrství a Ostatní. Tyto kategorie poskytují strukturovaný rámec pro všechny předměty napříč platformou.'),
  ('cs', 'doc_leaderboard_title', 'Globální žebříček'),
  ('cs', 'doc_leaderboard_desc', 'Soutěžte s ostatními studenty z celého světa! Získávejte XP dokončováním lekcí s kartami a stoupejte v žebříčku. Vaše pozice se aktualizuje v reálném čase, jakmile ovládnete nové předměty.'),
  ('cs', 'doc_friends_title', 'Přátelé a pozvánky'),
  ('cs', 'doc_friends_desc', 'Učení je lepší společně! Pozvěte přátele do Aliolo prostřednictvím svého profilu. Můžete sledovat pokrok toho druhého a zůstat motivovaní tím, že uvidíte, kdo si udržuje nejdelší sérii.'),
  ('cs', 'doc_streaks_title', 'Systém sérií'),
  ('cs', 'doc_streaks_desc', 'Klíčem je důslednost! Plňte svůj denní cíl každý den, abyste si budovali sérii. Nevynechejte ani den, jinak se série vynuluje.'),
  ('cs', 'doc_goals_title', 'Denní cíle'),
  ('cs', 'doc_goals_desc', 'V nastavení si určete svůj denní cíl dokončení karet. Změny cíle se projeví až od příštího dne.'),
  ('cs', 'doc_public_title', 'Veřejné vs. soukromé'),
  ('cs', 'doc_public_desc', 'Předměty mohou být soukromé (viditelné pouze pro vás) nebo veřejné. Veřejný obsah je sdílen s celou komunitou Aliolo, což umožňuje komukoli objevovat a učit se z vašich výtvorů.'),
  ('cs', 'doc_sync_title', 'Synchronizace s cloudem'),
  ('cs', 'doc_sync_desc', 'Váš pokrok se automaticky synchronizuje s cloudem. Můžete přepínat mezi webovou a desktopovou verzí, aniž byste přišli o svou sérii.'),
  ('cs', 'doc_feedback_title', 'Systém zpětné vazby'),
  ('cs', 'doc_feedback_desc', 'Pomozte nám se zlepšovat! Pomocí ikony zpětné vazby (Icons.feedback) u libovolného předmětu nebo složky nahlaste problémy. Můžete také poslat obecnou zpětnou vazbu k aplikaci prostřednictvím sekce Podpora.'),
  ('cs', 'doc_lang_title', 'Jazyk učení'),
  ('cs', 'doc_lang_desc', 'Před výběrem předmětu si v horním menu vždy vyberte preferovaný jazyk učení. Tím zajistíte načtení správného audia a překladů.'),
  ('cs', 'doc_filters_title', 'Hledání a filtry'),
  ('cs', 'doc_filters_desc', 'Rychle najděte obsah pomocí vyhledávacího panelu. Můžete filtrovat podle věkové skupiny (od raného věku po pokročilé) nebo zúžit pohled na konkrétní sbírky a složky.'),
  ('cs', 'doc_flashcards_title', 'Vizuální kartičky'),
  ('cs', 'doc_flashcards_desc', 'Každý předmět obsahuje sadu karet. I když jsou obrázky a audio podporovány, jsou volitelné – obsah může být čistě textový nebo dynamicky generovaný.'),
  ('cs', 'doc_study_modes_title', 'Adaptivní studijní režimy'),
  ('cs', 'doc_study_modes_desc', 'Aliolo podporuje různé režimy testování na základě vašeho obsahu: Obrázek na text, Audio na obrázek a Text na audio. Tento multismyslový přístup zajistí, že předměty ovládnete ze všech úhlů.'),
  ('cs', 'doc_testing_title', 'Interaktivní testování'),
  ('cs', 'doc_testing_desc', 'Vyzvěte se otázkami s výběrem odpovědí (MCQ). Aplikace bude po vaší odpovědi automaticky pokračovat, což vám pomůže učit se rychleji.'),
  ('cs', 'doc_autoplay_title', 'Automatické učení'),
  ('cs', 'doc_autoplay_desc', 'Aplikace může po vaší odpovědi automaticky přejít na další kartu. Správné odpovědi čekají 1 s, zatímco nesprávné 2 s, abyste si je mohli prohlédnout.'),
  ('cs', 'doc_math_title', 'Matematické předměty'),
  ('cs', 'doc_math_desc', 'Matematické předměty využívají specializované enginy ke generování vizualizací karet v reálném čase. Tyto předměty obsahují jedinečné režimy učení a testování přizpůsobené konkrétním matematickým konceptům, což zajišťuje efektivnější prostředí pro procvičování.'),
  ('cs', 'doc_organization_title', 'Organizace obsahu'),
  ('cs', 'doc_organization_desc', 'Pomocí složek můžete seskupovat související předměty. Můžete také vytvářet sbírky a organizovat předměty do vybraných cest.'),
  ('cs', 'doc_creation_title', 'Vytváření předmětů a karet'),
  ('cs', 'doc_creation_desc', 'Vytvářejte vlastní předměty a přidávejte vizuální kartičky. Každá karta podporuje obrázek a volitelný audio soubor pro výslovnost.'),
  ('cs', 'doc_collections_purpose_title', 'Účel sbírek'),
  ('cs', 'doc_collections_purpose_desc', 'Sbírky jsou vybrané cesty, které seskupují předměty. Když spustíte lekci ze sbírky, systém namíchá karty ze všech zahrnutých předmětů, aby poskytl náhodný a komplexní test.'),
  ('cs', 'doc_card_scope_title', 'Kde karty žijí'),
  ('cs', 'doc_card_scope_desc', 'Karty jsou základními kameny učení a vždy patří ke konkrétnímu předmětu. I když můžete předměty organizovat do složek nebo sbírek, samotné karty musí být vytvořeny v rámci předmětu.'),
  ('cs', 'doc_localization_ui_title', 'Přidávání překladů'),
  ('cs', 'doc_localization_ui_desc', 'Chcete-li přidat lokalizovaná data, jednoduše klepněte na ikonu kódu jazyka (např. EN, ES, FR) v záhlaví editoru. To vám umožní zadat konkrétní názvy, popisy a obsah karet pro každý podporovaný jazyk. Karta „Globální“ slouží jako primární záloha, pokud není k dispozici žádný konkrétní překlad.'),
  ('cs', 'doc_localization_details_title', 'Jak funguje lokalizace'),
  ('cs', 'doc_localization_details_desc', '„Globální“ jazyk je vaše primární záloha – může to být jakýkoli jazyk, který si vyberete. Pokud poskytnete konkrétní překlady (jako angličtinu nebo španělštinu), přepíší globální data pouze tehdy, když si uživatel zvolí tento konkrétní jazyk uživatelského rozhraní.'),
  ('cs', 'doc_json_title', 'JSON lokalizace'),
  ('cs', 'doc_json_desc', 'Pokročilí tvůrci mohou pomocí dat JSON poskytovat lokalizované názvy a popisy, díky čemuž jsou předměty přístupné ve všech podporovaných jazycích.'),
  ('cs', 'doc_media_title', 'Limity pro nahrávání médií'),
  ('cs', 'doc_media_desc', 'Pro zajištění rychlé synchronizace udržujte obrázky pod 5 MB a audio soubory pod 10 MB.'),

  ('da', 'doc_welcome_title', 'Velkommen til Aliolo'),
  ('da', 'doc_welcome_desc', 'Aliolo er en visuel læringsplatform designet til at hjælpe dig med at mestre emner gennem flashcards og interaktiv test.'),
  ('da', 'doc_pillars_title', 'De 8 kernesøjler'),
  ('da', 'doc_pillars_desc', 'Alt indhold i Aliolo er organiseret i 8 grundlæggende søjler: Akademisk og professionel, Verden, Natur, Menneskekroppen, Humaniora, Fritid, Ingeniørvidenskab og Andet. Disse kategorier giver en struktureret ramme for alle emner på platformen.'),
  ('da', 'doc_leaderboard_title', 'Global rangliste'),
  ('da', 'doc_leaderboard_desc', 'Konkurrer med elever over hele verden! Optjen XP ved at gennemføre kortsessioner og kravl op ad ranglisten. Din position opdateres i realtid, efterhånden som du mestrer nye emner.'),
  ('da', 'doc_friends_title', 'Venner og invitationer'),
  ('da', 'doc_friends_desc', 'Læring er bedre sammen! Inviter venner til Aliolo via din profil. I kan følge hinandens fremskridt og forblive motiverede ved at se, hvem der opretholder den længste streak.'),
  ('da', 'doc_streaks_title', 'Streak-system'),
  ('da', 'doc_streaks_desc', 'Konsistens er nøglen! Gennemfør dit daglige mål hver dag for at opbygge din streak. Gå ikke glip af en dag, ellers nulstilles streaken.'),
  ('da', 'doc_goals_title', 'Daglige mål'),
  ('da', 'doc_goals_desc', 'Indstil dit daglige mål for kortfærdiggørelse i indstillingerne. Ændringer af dit mål træder i kraft fra næste dag.'),
  ('da', 'doc_public_title', 'Offentlig vs. privat'),
  ('da', 'doc_public_desc', 'Emner kan være private (kun synlige for dig) eller offentlige. Offentligt indhold deles med hele Aliolo-fællesskabet, hvilket giver alle mulighed for at opdage og lære af dine kreationer.'),
  ('da', 'doc_sync_title', 'Cloud-synkronisering'),
  ('da', 'doc_sync_desc', 'Dine fremskridt synkroniseres automatisk til skyen. Du kan skifte mellem web- og desktopversioner uden at miste din streak.'),
  ('da', 'doc_feedback_title', 'Feedback-system'),
  ('da', 'doc_feedback_desc', 'Hjælp os med at forbedre os! Brug feedback-ikonet (Icons.feedback) på et emne oder en mappe for at rapportere problemer. Du kan også sende generel app-feedback via supportsektionen.'),
  ('da', 'doc_lang_title', 'Læringssprog'),
  ('da', 'doc_lang_desc', 'Vælg altid dit foretrukne læringssprog i topmenuen, før du vælger et emne. Dette sikrer, at den korrekte lyd og oversættelser indlæses.'),
  ('da', 'doc_filters_title', 'Søgning og filtre'),
  ('da', 'doc_filters_desc', 'Find hurtigt indhold ved hjælp af søgefeltet. Du kan filtrere efter aldersgruppe (tidlig til avanceret) eller indsnævre din visning til specifikke samlinger og mapper.'),
  ('da', 'doc_flashcards_title', 'Visuelle flashcards'),
  ('da', 'doc_flashcards_desc', 'Hvert emne indeholder et sæt kort. Selvom billeder og lyd understøttes, er de valgfrie – indhold kan være rent tekstuelt eller dynamisk genereret.'),
  ('da', 'doc_study_modes_title', 'Adaptive studietilstande'),
  ('da', 'doc_study_modes_desc', 'Aliolo understøtter forskellige testtilstande baseret på dit indhold: Billede-til-tekst, Lyd-til-billede og Tekst-til-lyd. Denne multisensoriske tilgang sikrer, at du mestrer emner fra alle vinkler.'),
  ('da', 'doc_testing_title', 'Interaktiv test'),
  ('da', 'doc_testing_desc', 'Udfordr dig selv med multiple-choice spørgsmål (MCQ). Appen vil automatisk gå videre, når du svarer, hvilket hjælper dig med at lære hurtigere.'),
  ('da', 'doc_autoplay_title', 'Auto-play læring'),
  ('da', 'doc_autoplay_desc', 'Appen kan automatisk gå videre til næste kort, når du har svaret. Korrekte svar venter 1 sek., mens forkerte venter 2 sek. for at lade dig gennemse.'),
  ('da', 'doc_math_title', 'Matematiske emner'),
  ('da', 'doc_math_desc', 'Matematiske emner bruger specialiserede motorer til at generere kortvisualiseringer i realtid. Disse emner har unikke lærings- og testtilstande, der er skræddersyet til specifikke matematiske koncepter, hvilket sikrer et mere effektivt øvelsesmiljø.'),
  ('da', 'doc_organization_title', 'Organisering af indhold'),
  ('da', 'doc_organization_desc', 'Brug mapper til at gruppere relaterede emner sammen. Du kan også oprette samlinger for at organisere emner i kuraterede stier.'),
  ('da', 'doc_creation_title', 'Oprettelse af emner og kort'),
  ('da', 'doc_creation_desc', 'Opret dine egne emner og tilføj visuelle flashcards. Hvert kort understøtter et billede og en valgfri lydfil til udtale.'),
  ('da', 'doc_collections_purpose_title', 'Formålet med samlinger'),
  ('da', 'doc_collections_purpose_desc', 'Samlinger are kuraterede stier, der grupperer emner sammen. Når du starter en session fra en samling, blander systemet kort fra alle inkluderede emner for at give en randomiseret, omfattende test.'),
  ('da', 'doc_card_scope_title', 'Hvor kort bor'),
  ('da', 'doc_card_scope_desc', 'Kort er byggestenene i læring og tilhører altid et bestemt emne. Selvom du kan organisere emner i mapper eller samlinger, skal selve kortene oprettes i et emne.'),
  ('da', 'doc_localization_ui_title', 'Tilføjelse af oversættelser'),
  ('da', 'doc_localization_ui_desc', 'For at tilføje lokaliserede data skal du blot trykke på sprogkode-ikonet (f.eks. EN, ES, FR) i editorens overskrift. Dette giver dig mulighed for at angive specifikke navne, beskrivelser og kortindhold for hvert understøttet sprog. Fanen "Global" fungerer som det primære fallback, hvis der ikke gives en specifik oversættelse.'),
  ('da', 'doc_localization_details_title', 'Sådan fungerer lokalisering'),
  ('da', 'doc_localization_details_desc', '"Global"-sproget er dit primære fallback – det kan være et hvilket som helst sprog, du vælger. Hvis du leverer specifikke oversættelser (som engelsk eller spansk), vil de kun tilsidesætte de globale data, når en bruger vælger det specifikke UI-sprog.'),
  ('da', 'doc_json_title', 'JSON-lokalisering'),
  ('da', 'doc_json_desc', 'Avancerede skabere kan bruge JSON-data til at levere lokaliserede navne og beskrivelser, hvilket gør emner tilgængelige på alle understøttede sprog.'),
  ('da', 'doc_media_title', 'Grænser for upload af medier'),
  ('da', 'doc_media_desc', 'For at sikre hurtig synkronisering skal du holde billeder under 5 MB og lydfiler under 10 MB.'),

  ('de', 'doc_welcome_title', 'Willkommen bei Aliolo'),
  ('de', 'doc_welcome_desc', 'Aliolo ist eine visuelle Lernplattform, die Ihnen hilft, Themen durch Karteikarten und interaktive Tests zu meistern.'),
  ('de', 'doc_pillars_title', 'Die 8 Kernsäulen'),
  ('de', 'doc_pillars_desc', 'Alle Inhalte in Aliolo sind in 8 grundlegende Säulen unterteilt: Akademisch & Beruflich, Welt, Natur, Menschlicher Körper, Geisteswissenschaften, Freizeit, Ingenieurwesen und Sonstiges. Diese Kategorien bieten einen strukturierten Rahmen für alle Themen auf der Plattform.'),
  ('de', 'doc_leaderboard_title', 'Globale Bestenliste'),
  ('de', 'doc_leaderboard_desc', 'Messen Sie sich mit Lernenden weltweit! Verdienen Sie XP durch das Abschließen von Kartensitzungen und steigen Sie in der Rangliste auf. Ihre Position wird in Echtzeit aktualisiert, während Sie neue Themen meistern.'),
  ('de', 'doc_friends_title', 'Freunde & Einladungen'),
  ('de', 'doc_friends_desc', 'Gemeinsam lernt es sich besser! Laden Sie Freunde über Ihr Profil zu Aliolo ein. Sie können den Fortschritt der anderen verfolgen und motiviert bleiben, indem Sie sehen, wer die längste Streak hält.'),
  ('de', 'doc_streaks_title', 'Streak-System'),
  ('de', 'doc_streaks_desc', 'Beständigkeit ist der Schlüssel! Erfüllen Sie jeden Tag Ihr Tagesziel, um Ihre Streak aufzubauen. Verpassen Sie keinen Tag, sonst wird die Streak zurückgesetzt.'),
  ('de', 'doc_goals_title', 'Tagesziele'),
  ('de', 'doc_goals_desc', 'Legen Sie in den Einstellungen Ihr tägliches Ziel für das Abschließen von Karten fest. Änderungen an Ihrem Ziel werden ab dem nächsten Tag wirksam.'),
  ('de', 'doc_public_title', 'Öffentlich vs. Privat'),
  ('de', 'doc_public_desc', 'Themen können privat (nur für Sie sichtbar) oder öffentlich sein. Öffentliche Inhalte werden mit der gesamten Aliolo-Community geteilt, sodass jeder Ihre Kreationen entdecken und von ihnen lernen kann.'),
  ('de', 'doc_sync_title', 'Cloud-Synchronisierung'),
  ('de', 'doc_sync_desc', 'Ihr Fortschritt wird automatisch mit der Cloud synchronisiert. Sie können zwischen Web- und Desktop-Versionen wechseln, ohne Ihre Streak zu verlieren.'),
  ('de', 'doc_feedback_title', 'Feedback-System'),
  ('de', 'doc_feedback_desc', 'Helfen Sie uns, besser zu werden! Verwenden Sie das Feedback-Symbol (Icons.feedback) bei einem Thema oder Ordner, um Probleme zu melden. Sie können auch allgemeines App-Feedback über den Support-Bereich senden.'),
  ('de', 'doc_lang_title', 'Lernsprache'),
  ('de', 'doc_lang_desc', 'Wählen Sie im oberen Menü immer Ihre bevorzugte Lernsprache aus, bevor Sie ein Thema auswählen. Dies stellt sicher, dass die korrekten Audioaufnahmen und Übersetzungen geladen werden.'),
  ('de', 'doc_filters_title', 'Suche & Filter'),
  ('de', 'doc_filters_desc', 'Finden Sie Inhalte schnell über die Suchleiste. Sie können nach Altersgruppen (Früh bis Fortgeschritten) filtern oder Ihre Ansicht auf bestimmte Sammlungen und Ordner einschränken.'),
  ('de', 'doc_flashcards_title', 'Visuelle Karteikarten'),
  ('de', 'doc_flashcards_desc', 'Jedes Thema enthält einen Satz Karten. Bilder und Audio werden zwar unterstützt, sind aber optional – Inhalte können rein textbasiert sein oder dynamisch generiert werden.'),
  ('de', 'doc_study_modes_title', 'Adaptive Lernmodi'),
  ('de', 'doc_study_modes_desc', 'Aliolo unterstützt verschiedene Testmodi basierend auf Ihren Inhalten: Bild-zu-Text, Audio-zu-Bild und Text-zu-Audio. Dieser multisensorische Ansatz stellt sicher, dass Sie Themen aus jedem Blickwinkel meistern.'),
  ('de', 'doc_testing_title', 'Interaktives Testen'),
  ('de', 'doc_testing_desc', 'Fordern Sie sich mit Multiple-Choice-Fragen (MCQ) heraus. Die App schaltet automatisch weiter, wenn Sie antworten, was Ihnen hilft, schneller zu lernen.'),
  ('de', 'doc_autoplay_title', 'Auto-Play-Lernen'),
  ('de', 'doc_autoplay_desc', 'Die App kann nach Ihrer Antwort automatisch zur nächsten Karte weitergehen. Richtige Antworten warten 1s, während falsche 2s warten, damit Sie sie überprüfen können.'),
  ('de', 'doc_math_title', 'Mathematische Themen'),
  ('de', 'doc_math_desc', 'Mathematische Themen verwenden spezialisierte Engines, um Kartenvisualisierungen in Echtzeit zu generieren. Diese Themen bieten einzigartige Lern- und Testmodi, die auf spezifische mathematische Konzepte zugeschnitten sind und eine effektivere Übungsumgebung gewährleisten.'),
  ('de', 'doc_organization_title', 'Inhalte organisieren'),
  ('de', 'doc_organization_desc', 'Verwenden Sie Ordner, um verwandte Themen zusammenzufassen. Sie können auch Sammlungen erstellen, um Themen in kuratierten Pfaden zu organisieren.'),
  ('de', 'doc_creation_title', 'Themen & Karten erstellen'),
  ('de', 'doc_creation_desc', 'Erstellen Sie Ihre eigenen Themen und fügen Sie visuelle Karteikarten hinzu. Jede Karte unterstützt ein Bild und eine optionale Audiodatei für die Aussprache.'),
  ('de', 'doc_collections_purpose_title', 'Zweck von Sammlungen'),
  ('de', 'doc_collections_purpose_desc', 'Sammlungen sind kuratierte Pfade, die Themen zusammenfassen. Wenn Sie eine Sitzung aus einer Sammlung starten, mischt das System Karten aus allen enthaltenen Themen, um einen randomisierten, umfassenden Test zu bieten.'),
  ('de', 'doc_card_scope_title', 'Wo Karten zu Hause sind'),
  ('de', 'doc_card_scope_desc', 'Karten sind die Bausteine des Lernens und gehören immer zu einem bestimmten Thema. Während Sie Themen in Ordnern oder Sammlungen organisieren können, müssen Karten selbst innerhalb eines Themas erstellt werden.'),
  ('de', 'doc_localization_ui_title', 'Übersetzungen hinzufügen'),
  ('de', 'doc_localization_ui_desc', 'Um lokalisierte Daten hinzuzufügen, tippen Sie einfach auf das Sprachcode-Symbol (z. B. EN, ES, FR) in der Kopfzeile des Editors. Dies ermöglicht es Ihnen, spezifische Namen, Beschreibungen und Karteninhalte für jede unterstützte Sprache bereitzustellen. Der Tab „Global“ dient als primärer Fallback, wenn keine spezifische Übersetzung bereitgestellt wird.'),
  ('de', 'doc_localization_details_title', 'Wie Lokalisierung funktioniert'),
  ('de', 'doc_localization_details_desc', 'Die Sprache „Global“ ist Ihr primärer Fallback – es kann jede Sprache sein, die Sie wählen. Wenn Sie spezifische Übersetzungen (wie Englisch oder Spanisch) bereitstellen, überschreiben diese die globalen Daten nur dann, wenn ein Benutzer diese spezifische UI-Sprache auswählt.'),
  ('de', 'doc_json_title', 'JSON-Lokalisierung'),
  ('de', 'doc_json_desc', 'Fortgeschrittene Ersteller können JSON-Daten verwenden, um lokalisierte Namen und Beschreibungen bereitzustellen und Themen so in allen unterstützten Sprachen zugänglich zu machen.'),
  ('de', 'doc_media_title', 'Upload-Limits für Medien'),
  ('de', 'doc_media_desc', 'Um eine schnelle Synchronisierung zu gewährleisten, sollten Bilder unter 5 MB und Audiodateien unter 10 MB bleiben.'),

  ('et', 'doc_welcome_title', 'Tere tulemast Aliolosse'),
  ('et', 'doc_welcome_desc', 'Aliolo on visuaalne õppeplatvorm, mis on loodud aitama teil õppeaineid omandada flashcardide ja interaktiivse testimise kaudu.'),
  ('et', 'doc_pillars_title', '8 põhisammast'),
  ('et', 'doc_pillars_desc', 'Kogu Aliolo sisu on jagatud 8 põhisambasse: Akadeemiline ja professionaalne, Maailm, Loodus, Inimkeha, Humanitaarteadused, Vaba aeg, Inseneeria ja Muu. Need kategooriad pakuvad struktureeritud raamistikku kõigile platvormi õppeainetele.'),
  ('et', 'doc_leaderboard_title', 'Globaalne edetabel'),
  ('et', 'doc_leaderboard_desc', 'Võistlege õppijatega üle maailma! Teenige XP-d kaartide sessioonide läbimisel ja tõuske edetabelis. Teie positsioon uueneb reaalajas uute õppeainete omandamisel.'),
  ('et', 'doc_friends_title', 'Sõbrad ja kutsed'),
  ('et', 'doc_friends_desc', 'Koos õppimine on parem! Kutsuge sõpru Aliolosse oma profiili kaudu. Saate jälgida üksteise progressi ja püsida motiveeritud nähes, kes hoiab pikimat streak-i.'),
  ('et', 'doc_streaks_title', 'Streak süsteem'),
  ('et', 'doc_streaks_desc', 'Järjepidevus on võti! Täitke oma päevaeesmärk iga päev, et ehitada oma streak-i. Ärge vahele jätke ühtegi päeva, muidu streak nullitakse.'),
  ('et', 'doc_goals_title', 'Päevaeesmärgid'),
  ('et', 'doc_goals_desc', 'Määrake seadetes oma igapäevane kaartide läbimise eesmärk. Eesmärgi muudatused jõustuvad järgmisest päevast.'),
  ('et', 'doc_public_title', 'Avalik vs privaatne'),
  ('et', 'doc_public_desc', 'Õppeained võivad olla privaatsed (nähtavad ainult teile) või avalikud. Avalik sisu jagatakse kogu Aliolo kogukonnaga, võimaldades kõigil teie loometööd avastada ja sellest õppida.'),
  ('et', 'doc_sync_title', 'Pilvesünkroonimine'),
  ('et', 'doc_sync_desc', 'Teie progress sünkroonitakse automaatselt pilvega. Saate vahetada veebi- ja töölaua versioonide vahel ilma oma streak-i kaotamata.'),
  ('et', 'doc_feedback_title', 'Tagasiside süsteem'),
  ('et', 'doc_feedback_desc', 'Aidake meil täiustuda! Kasutage tagasiside ikooni (Icons.feedback) mis tahes õppeaine või kausta juures probleemidest teatamiseks. Üldist tagasisidet rakenduse kohta saate saata ka toe sektsiooni kaudu.'),
  ('et', 'doc_lang_title', 'Õppekeel'),
  ('et', 'doc_lang_desc', 'Valige ülemises menüüs alati oma eelistatud õppekeel enne õppeaine valimist. See tagab õige audio ja tõlgete laadimise.'),
  ('et', 'doc_filters_title', 'Otsing ja filtrid'),
  ('et', 'doc_filters_desc', 'Leidke sisu kiiresti otsinguriba abil. Saate filtreerida vanuserühma järgi (varajasest kuni edasijõudnuni) või kitsendada vaadet konkreetsetele kollektsioonidele ja kaustadele.'),
  ('et', 'doc_flashcards_title', 'Visuaalsed flashcardid'),
  ('et', 'doc_flashcards_desc', 'Iga õppeaine sisaldab kaartide komplekti. Kuigi pildid ja audio on toetatud, on need valikulised – sisu võib olla puhtalt tekstiline või dünaamiliselt genereeritud.'),
  ('et', 'doc_study_modes_title', 'Adaptiivsed õpperežiimid'),
  ('et', 'doc_study_modes_desc', 'Aliolo toetab erinevaid testimisrežiime vastavalt teie sisule: pilt-tekstiks, audio-pildiks ja tekst-audioks. See meelteülene lähenemine tagab, et omandate õppeained igast küljest.'),
  ('et', 'doc_testing_title', 'Interaktiivne testimine'),
  ('et', 'doc_testing_desc', 'Pange end proovile valikvastustega küsimustega (MCQ). Rakendus liigub vastamisel automaatselt edasi, aidates teil kiiremini õppida.'),
  ('et', 'doc_autoplay_title', 'Automaatne esitamine'),
  ('et', 'doc_autoplay_desc', 'Rakendus saab pärast vastamist automaatselt järgmisele kaardile edasi liikuda. Õiged vastused ootavad 1 s, valed 2 s, et saaksite üle vaadata.'),
  ('et', 'doc_math_title', 'Matemaatilised õppeained'),
  ('et', 'doc_math_desc', 'Matemaatilised õppeained kasutavad spetsiaalseid mootoreid kaartide visualiseerimiseks reaalajas. Need õppeained sisaldavad ainulaadseid õppe- ja testimisrežiime, mis on kohandatud konkreetsetele matemaatilistele kontseptsioonidele, tagades tõhusama harjutuskeskkonna.'),
  ('et', 'doc_organization_title', 'Sisu organiseerimine'),
  ('et', 'doc_organization_desc', 'Kasutage kaustu seotud õppeainete rühmitamiseks. Saate luua ka kollektsioone, et organiseerida õppeaineid kureeritud radadeks.'),
  ('et', 'doc_creation_title', 'Õppeainete ja kaartide loomine'),
  ('et', 'doc_creation_desc', 'Looge oma õppeaineid ja lisage visuaalseid flashcarde. Iga kaart toetab pilti ja valikulist audiofaili häälduse jaoks.'),
  ('et', 'doc_collections_purpose_title', 'Kollektsioonide eesmärk'),
  ('et', 'doc_collections_purpose_desc', 'Kollektsioonid on kureeritud rajad, mis rühmitavad õppeaineid. Kui alustate sessiooni kollektsioonist, segab süsteem kõigi kaasatud õppeainete kaarte, et pakkuda juhuslikku ja terviklikku testi.'),
  ('et', 'doc_card_scope_title', 'Kus kaardid asuvad'),
  ('et', 'doc_card_scope_desc', 'Kaardid on õppimise ehituskivid ja kuuluvad alati konkreetse õppeaine juurde. Kuigi saate organiseerida õppeaineid kaustadesse või kollektsioonidesse, tuleb kaardid ise luua õppeaine sees.'),
  ('et', 'doc_localization_ui_title', 'Tõlgete lisamine'),
  ('et', 'doc_localization_ui_desc', 'Lokaliseeritud andmete lisamiseks puudutage lihtsalt redaktori päises keelekoodi ikooni (nt EN, ES, FR). See võimaldab teil pakkuda konkreetseid nimesid, kirjeldusi ja kaardisisu iga toetatud keele jaoks. Vahekaart "Global" toimib peamise varuvariandina, kui konkreetset tõlget pole esitatud.'),
  ('et', 'doc_localization_details_title', 'Kuidas lokaliseerimine töötab'),
  ('et', 'doc_localization_details_desc', '"Global" keel on teie peamine varuvariant – see võib olla mis tahes keel, mille valite. Kui pakute konkreetseid tõlkeid (näiteks inglise või hispaania keeles), tühistavad need globaalsed andmed ainult siis, kui kasutaja valib selle konkreetse UI keele.'),
  ('et', 'doc_json_title', 'JSON-lokaliseerimine'),
  ('et', 'doc_json_desc', 'Edasijõudnud loojad saavad kasutada JSON-andmeid lokaliseeritud nimede ja kirjelduste pakkumiseks, muutes õppeained kättesaadavaks kõigis toetatud keeltes.'),
  ('et', 'doc_media_title', 'Meedia üleslaadimise piirangud'),
  ('et', 'doc_media_desc', 'Kiire sünkroonimise tagamiseks hoidke pildid alla 5 MB ja audiofailid alla 10 MB.'),

  ('es', 'doc_welcome_title', 'Bienvenido a Aliolo'),
  ('es', 'doc_welcome_desc', 'Aliolo es una plataforma de aprendizaje visual diseñada para ayudarte a dominar temas mediante tarjetas y pruebas interactivas.'),
  ('es', 'doc_pillars_title', 'Los 8 pilares fundamentales'),
  ('es', 'doc_pillars_desc', 'Todo el contenido de Aliolo se organiza en 8 pilares fundamentales: Académico y profesional, Mundo, Naturaleza, Cuerpo humano, Humanidades, Ocio, Ingeniería y Otros. Estas categorías proporcionan un marco estructurado para todos los temas de la plataforma.'),
  ('es', 'doc_leaderboard_title', 'Clasificación global'),
  ('es', 'doc_leaderboard_desc', '¡Compite con estudiantes de todo el mundo! Gana XP completando sesiones de tarjetas y sube de rango. Tu posición se actualiza en tiempo real a medida que dominas nuevos temas.'),
  ('es', 'doc_friends_title', 'Amigos e invitaciones'),
  ('es', 'doc_friends_desc', '¡Aprender es mejor juntos! Invita a amigos a Aliolo a través de tu perfil. Pueden seguir el progreso de los demás y mantenerse motivados viendo quién mantiene la racha más larga.'),
  ('es', 'doc_streaks_title', 'Sistema de rachas'),
  ('es', 'doc_streaks_desc', '¡La constancia es la clave! Completa tu objetivo diario todos los días para crear tu racha. No faltes ni un día o la racha se reiniciará.'),
  ('es', 'doc_goals_title', 'Objetivos diarios'),
  ('es', 'doc_goals_desc', 'Establece tu objetivo diario de finalización de tarjetas en los ajustes. Los cambios en tu objetivo entrarán en vigor a partir del día siguiente.'),
  ('es', 'doc_public_title', 'Público vs. Privado'),
  ('es', 'doc_public_desc', 'Los temas pueden ser privados (visibles solo para ti) o públicos. El contenido público se comparte con toda la comunidad de Aliolo, lo que permite que todos descubran y aprendan de tus creaciones.'),
  ('es', 'doc_sync_title', 'Sincronización en la nube'),
  ('es', 'doc_sync_desc', 'Tu progreso se sincroniza automáticamente en la nube. Puedes cambiar entre las versiones web y de escritorio sin perder tu racha.'),
  ('es', 'doc_feedback_title', 'Sistema de comentarios'),
  ('es', 'doc_feedback_desc', '¡Ayúdanos a mejorar! Utiliza el icono de comentarios (Icons.feedback) en cualquier tema o carpeta para informar de problemas. También puedes enviar comentarios generales sobre la aplicación a través de la sección de soporte.'),
  ('es', 'doc_lang_title', 'Idioma de aprendizaje'),
  ('es', 'doc_lang_desc', 'Selecciona siempre tu idioma de aprendizaje preferido en el menú superior antes de seleccionar un tema. Esto garantiza que se carguen el audio y las traducciones correctos.'),
  ('es', 'doc_filters_title', 'Búsqueda y filtros'),
  ('es', 'doc_filters_desc', 'Encuentra contenido rápidamente con la barra de búsqueda. Puedes filtrar por grupo de edad (desde inicial hasta avanzado) o limitar la vista a colecciones y carpetas específicas.'),
  ('es', 'doc_flashcards_title', 'Tarjetas visuales'),
  ('es', 'doc_flashcards_desc', 'Cada tema contiene un conjunto de tarjetas. Aunque se admiten imágenes y audio, son opcionales: el contenido puede ser puramente textual o generarse dinámicamente.'),
  ('es', 'doc_study_modes_title', 'Modos de estudio adaptativos'),
  ('es', 'doc_study_modes_desc', 'Aliolo admite varios modos de prueba basados en tu contenido: Imagen a texto, Audio a imagen y Texto a audio. Este enfoque multisensorial garantiza que domines los temas desde todos los ángulos.'),
  ('es', 'doc_testing_title', 'Pruebas interactivas'),
  ('es', 'doc_testing_desc', 'Ponte a prueba con preguntas de opción múltiple (MCQ). La aplicación avanzará automáticamente a medida que respondas, lo que te ayudará a aprender más rápido.'),
  ('es', 'doc_autoplay_title', 'Aprendizaje con reproducción automática'),
  ('es', 'doc_autoplay_desc', 'La aplicación puede avanzar automáticamente a la siguiente tarjeta después de que respondas. Las respuestas correctas esperan 1 s, mientras que las incorrectas esperan 2 s para que puedas revisarlas.'),
  ('es', 'doc_math_title', 'Temas matemáticos'),
  ('es', 'doc_math_desc', 'Los temas matemáticos utilizan motores especializados para generar visualizaciones de tarjetas en tiempo real. Estos temas cuentan con modos de aprendizaje y prueba únicos adaptados a conceptos matemáticos específicos, lo que garantiza un entorno de práctica más eficaz.'),
  ('es', 'doc_organization_title', 'Organización del contenido'),
  ('es', 'doc_organization_desc', 'Utiliza carpetas para agrupar temas relacionados. También puedes crear colecciones para organizar temas en rutas seleccionadas.'),
  ('es', 'doc_creation_title', 'Creación de temas y tarjetas'),
  ('es', 'doc_creation_desc', 'Crea tus propios temas y añade tarjetas visuales. Cada tarjeta admite una imagen y un archivo de audio opcional para la pronunciación.'),
  ('es', 'doc_collections_purpose_title', 'El propósito de las colecciones'),
  ('es', 'doc_collections_purpose_desc', 'Las colecciones son rutas seleccionadas que agrupan temas. Cuando inicias una sesión desde una colección, el sistema mezcla tarjetas de todos los temas incluidos para ofrecer una prueba completa y aleatoria.'),
  ('es', 'doc_card_scope_title', 'Dónde viven las tarjetas'),
  ('es', 'doc_card_scope_desc', 'Las tarjetas son los pilares del aprendizaje y siempre pertenecen a un tema específico. Aunque puedes organizar los temas en carpetas o colecciones, las tarjetas deben crearse dentro de un tema.'),
  ('es', 'doc_localization_ui_title', 'Añadir traducciones'),
  ('es', 'doc_localization_ui_desc', 'Para añadir datos localizados, solo tienes que tocar el icono del código de idioma (por ejemplo, EN, ES, FR) en el encabezado del editor. Esto te permite proporcionar nombres, descripciones y contenido de tarjetas específicos para cada idioma admitido. La pestaña "Global" sirve como reserva principal si no se proporciona una traducción específica.'),
  ('es', 'doc_localization_details_title', 'Cómo funciona la localización'),
  ('es', 'doc_localization_details_desc', 'El idioma "Global" es tu reserva principal y puede ser cualquier idioma que elijas. Si proporcionas traducciones específicas (como inglés o español), estas anularán los datos globales solo cuando un usuario seleccione ese idioma específico de la interfaz de usuario.'),
  ('es', 'doc_json_title', 'Localización JSON'),
  ('es', 'doc_json_desc', 'Los creadores avanzados pueden utilizar datos JSON para proporcionar nombres y descripciones localizados, lo que hace que los temas sean accesibles en todos los idiomas admitidos.'),
  ('es', 'doc_media_title', 'Límites de subida de archivos'),
  ('es', 'doc_media_desc', 'Para garantizar una sincronización rápida, mantén las imágenes por debajo de 5 MB y los archivos de audio por debajo de 10 MB.'),

  ('fr', 'doc_welcome_title', 'Bienvenue sur Aliolo'),
  ('fr', 'doc_welcome_desc', 'Aliolo est une plateforme d''apprentissage visuel conçue pour vous aider à maîtriser des sujets grâce à des flashcards et des tests interactifs.'),
  ('fr', 'doc_pillars_title', 'Les 8 piliers fondamentaux'),
  ('fr', 'doc_pillars_desc', 'Tout le contenu d''Aliolo est organisé en 8 piliers fondamentaux : Académique et professionnel, Monde, Nature, Corps humain, Sciences humaines, Loisirs, Ingénierie et Autre. Ces catégories fournissent un cadre structuré pour tous les sujets sur la plateforme.'),
  ('fr', 'doc_leaderboard_title', 'Classement mondial'),
  ('fr', 'doc_leaderboard_desc', 'Affrontez des apprenants du monde entier ! Gagnez de l''XP en terminant des sessions de cartes et grimpez dans les rangs. Votre position est mise à jour en temps réel à mesure que vous maîtrisez de nouveaux sujets.'),
  ('fr', 'doc_friends_title', 'Amis et invitations'),
  ('fr', 'doc_friends_desc', 'L''apprentissage est meilleur à plusieurs ! Invite des amis sur Aliolo via votre profil. Vous pouvez suivre les progrès des uns et des autres et rester motivé en voyant qui maintient la plus longue série.'),
  ('fr', 'doc_streaks_title', 'Système de séries (Streaks)'),
  ('fr', 'doc_streaks_desc', 'La régularité est la clé ! Remplissez votre objectif quotidien chaque jour pour construire votre série. Ne manquez pas un jour, sinon la série sera réinitialisée.'),
  ('fr', 'doc_goals_title', 'Objectifs quotidiens'),
  ('fr', 'doc_goals_desc', 'Définissez votre objectif quotidien de cartes terminées dans les paramètres. Les modifications apportées à votre objectif prennent effet à partir du lendemain.'),
  ('fr', 'doc_public_title', 'Public vs Privé'),
  ('fr', 'doc_public_desc', 'Les sujets peuvent être privés (visibles uniquement par vous) ou publics. Le contenu public est partagé avec toute la communauté Aliolo, permettant à chacun de découvrir vos créations et d''apprendre grâce à elles.'),
  ('fr', 'doc_sync_title', 'Synchronisation Cloud'),
  ('fr', 'doc_sync_desc', 'Votre progression est automatiquement synchronisée avec le cloud. Vous pouvez basculer entre les versions web et de bureau sans perdre votre série.'),
  ('fr', 'doc_feedback_title', 'Système de commentaires'),
  ('fr', 'doc_feedback_desc', 'Aidez-nous à nous améliorer ! Utilisez l''icône de commentaire (Icons.feedback) sur n''importe quel sujet ou dossier pour signaler des problèmes. Vous pouvez également envoyer des commentaires généraux sur l''application via la section Support.'),
  ('fr', 'doc_lang_title', 'Langue d''apprentissage'),
  ('fr', 'doc_lang_desc', 'Sélectionnez toujours votre langue d''apprentissage préférée dans le menu du haut avant de sélectionner un sujet. Cela garantit le chargement de l''audio et des traductions appropriés.'),
  ('fr', 'doc_filters_title', 'Recherche et filtres'),
  ('fr', 'doc_filters_desc', 'Trouvez rapidement du contenu à l''aide de la barre de recherche. Vous pouvez filtrer par groupe d''âge (de "précoce" à "avancé") ou restreindre votre vue à des collections et dossiers spécifiques.'),
  ('fr', 'doc_flashcards_title', 'Flashcards visuelles'),
  ('fr', 'doc_flashcards_desc', 'Chaque sujet contient un ensemble de cartes. Bien que les images et l''audio soient pris en charge, ils sont facultatifs — le contenu peut être purement textuel ou généré dynamiquement.'),
  ('fr', 'doc_study_modes_title', 'Modes d''étude adaptatifs'),
  ('fr', 'doc_study_modes_desc', 'Aliolo prend en charge différents modes de test basés sur votre contenu : Image vers Texte, Audio vers Image et Texte vers Audio. Cette approche multisensorielle garantit que vous maîtrisez les sujets sous tous les angles.'),
  ('fr', 'doc_testing_title', 'Tests interactifs'),
  ('fr', 'doc_testing_desc', 'Mettez-vous au défi avec des questions à choix multiples (QCM). L''application avancera automatiquement au fur et à mesure que vous répondez, vous aidant à apprendre plus vite.'),
  ('fr', 'doc_autoplay_title', 'Apprentissage en lecture automatique'),
  ('fr', 'doc_autoplay_desc', 'L''application peut passer automatiquement à la carte suivante après votre réponse. Les bonnes réponses attendent 1 s, tandis que les mauvaises attendent 2 s pour vous permettre de réviser.'),
  ('fr', 'doc_math_title', 'Sujets mathématiques'),
  ('fr', 'doc_math_desc', 'Les sujets mathématiques utilisent des moteurs spécialisés pour générer des visualisations de cartes en temps réel. Ces sujets proposent des modes d''apprentissage et de test uniques adaptés à des concepts mathématiques spécifiques, garantissant un environnement d''entraînement plus efficace.'),
  ('fr', 'doc_organization_title', 'Organisation du contenu'),
  ('fr', 'doc_organization_desc', 'Utilisez des dossiers pour regrouper des sujets connexes. Vous pouvez également créer des collections pour organiser les sujets en parcours thématiques.'),
  ('fr', 'doc_creation_title', 'Création de sujets et de cartes'),
  ('fr', 'doc_creation_desc', 'Créez vos propres sujets et ajoutez des flashcards visuelles. Chaque carte prend en charge une image et un fichier audio optionnel pour la prononciation.'),
  ('fr', 'doc_collections_purpose_title', 'Le but des collections'),
  ('fr', 'doc_collections_purpose_desc', 'Les collections sont des parcours thématiques qui regroupent des sujets. Lorsque vous lancez une session à partir d''une collection, le système mélange les cartes de tous les sujets inclus pour proposer un test complet et aléatoire.'),
  ('fr', 'doc_card_scope_title', 'Où vivent les cartes'),
  ('fr', 'doc_card_scope_desc', 'Les cartes sont les briques de base de l''apprentissage et appartiennent toujours à un sujet spécifique. Bien que vous puissiez organiser les sujets en dossiers ou en collections, les cartes elles-mêmes doivent être créées au sein d''un sujet.'),
  ('fr', 'doc_localization_ui_title', 'Ajout de traductions'),
  ('fr', 'doc_localization_ui_desc', 'Pour ajouter des données localisées, appuyez simplement sur l''icône du code de langue (ex: EN, ES, FR) dans l''en-tête de l''éditeur. Cela vous permet de fournir des noms, des descriptions et du contenu de cartes spécifiques pour chaque langue prise en charge. L''onglet "Global" sert de solution de repli principale si aucune traduction spécifique n''est fournie.'),
  ('fr', 'doc_localization_details_title', 'Comment fonctionne la localisation'),
  ('fr', 'doc_localization_details_desc', 'La langue "Global" est votre solution de repli principale — elle peut être n''importe quelle langue de votre choix. Si vous fournissez des traductions spécifiques (comme l''anglais ou l''espagnol), elles ne remplaceront les données globales que lorsqu''un utilisateur sélectionne cette langue d''interface spécifique.'),
  ('fr', 'doc_json_title', 'Localisation JSON'),
  ('fr', 'doc_json_desc', 'Les créateurs avancés peuvent utiliser des données JSON pour fournir des noms et des descriptions localisés, rendant les sujets accessibles dans toutes les langues prises en charge.'),
  ('fr', 'doc_media_title', 'Limites de téléchargement de médias'),
  ('fr', 'doc_media_desc', 'Pour garantir une synchronisation rapide, gardez les images en dessous de 5 Mo et les fichiers audio en dessous de 10 Mo.'),

  ('pt', 'doc_welcome_title', 'Bem-vindo ao Aliolo'),
  ('pt', 'doc_welcome_desc', 'Aliolo é uma plataforma de aprendizagem visual concebida para o ajudar a dominar assuntos através de flashcards e testes interativos.'),
  ('pt', 'doc_pillars_title', 'Os 8 Pilares Fundamentais'),
  ('pt', 'doc_pillars_desc', 'Todo o conteúdo no Aliolo está organizado em 8 pilares fundamentais: Académico e Profissional, Mundo, Natureza, Corpo Humano, Humanidades, Lazer, Engenharia e Outros. Estas categorias fornecem um quadro estruturado para todos os assuntos na plataforma.'),
  ('pt', 'doc_leaderboard_title', 'Tabela de Classificação Global'),
  ('pt', 'doc_leaderboard_desc', 'Compita com alunos de todo o mundo! Ganhe XP completando sessões de cartões e suba na classificação. A sua posição é atualizada em tempo real à medida que domina novos assuntos.'),
  ('pt', 'doc_friends_title', 'Amigos e Convites'),
  ('pt', 'doc_friends_desc', 'Aprender é melhor em conjunto! Convide amigos para o Aliolo através do seu perfil. Pode acompanhar o progresso de cada um e manter-se motivado ao ver quem mantém a sequência mais longa.'),
  ('pt', 'doc_streaks_title', 'Sistema de Sequências (Streaks)'),
  ('pt', 'doc_streaks_desc', 'A consistência é a chave! Complete o seu objetivo diário todos os dias para construir a sua sequência. Não perca um dia, ou a sequência será reiniciada.'),
  ('pt', 'doc_goals_title', 'Objetivos Diários'),
  ('pt', 'doc_goals_desc', 'Defina o seu objetivo diário de conclusão de cartões nas definições. As alterações ao seu objetivo entram em vigor a partir do dia seguinte.'),
  ('pt', 'doc_public_title', 'Público vs Privado'),
  ('pt', 'doc_public_desc', 'Os assuntos podem ser privados (visíveis apenas para si) ou públicos. O conteúdo público é partilhado com toda a comunidade Aliolo, permitindo que todos descubram e aprendam com as suas criações.'),
  ('pt', 'doc_sync_title', 'Sincronização na Nuvem'),
  ('pt', 'doc_sync_desc', 'O seu progresso é sincronizado automaticamente com a nuvem. Pode alternar entre as versões web e desktop sem perder a sua sequência.'),
  ('pt', 'doc_feedback_title', 'Sistema de Feedback'),
  ('pt', 'doc_feedback_desc', 'Ajude-nos a melhorar! Use o ícone de feedback (Icons.feedback) em qualquer Assunto ou Pasta para comunicar problemas. Também pode enviar feedback geral sobre a aplicação através da secção de Suporte.'),
  ('pt', 'doc_lang_title', 'Idioma de Aprendizagem'),
  ('pt', 'doc_lang_desc', 'Selecione sempre o seu idioma de aprendizagem preferido no menu superior antes de selecionar um assunto. Isso garante que o áudio e as traduções corretas sejam carregados.'),
  ('pt', 'doc_filters_title', 'Pesquisa e Filtros'),
  ('pt', 'doc_filters_desc', 'Encontre conteúdo rapidamente usando a barra de pesquisa. Pode filtrar por Grupo de Idade (Precoce a Avançado) ou restringir a sua visualização a Coleções e Pastas específicas.'),
  ('pt', 'doc_flashcards_title', 'Flashcards Visuais'),
  ('pt', 'doc_flashcards_desc', 'Cada assunto contém um conjunto de cartões. Embora imagens e áudio sejam suportados, são opcionais—o conteúdo pode ser puramente textual ou gerado dinamicamente.'),
  ('pt', 'doc_study_modes_title', 'Modos de Estudo Adaptativos'),
  ('pt', 'doc_study_modes_desc', 'O Aliolo suporta vários modos de teste com base no seu conteúdo: Imagem para Texto, Áudio para Imagem e Texto para Áudio. Esta abordagem multissensorial garante que domina os assuntos de todos os ângulos.'),
  ('pt', 'doc_testing_title', 'Testes Interativos'),
  ('pt', 'doc_testing_desc', 'Desafie-se com perguntas de escolha múltipla (MCQ). A aplicação avançará automaticamente à medida que responde, ajudando-o a aprender mais depressa.'),
  ('pt', 'doc_autoplay_title', 'Aprendizagem com Reprodução Automática'),
  ('pt', 'doc_autoplay_desc', 'A aplicação pode avançar automaticamente para o próximo cartão depois de responder. As respostas corretas esperam 1s, enquanto as incorretas esperam 2s para permitir a sua revisão.'),
  ('pt', 'doc_math_title', 'Assuntos Matemáticos'),
  ('pt', 'doc_math_desc', 'Os assuntos matemáticos utilizam motores especializados para gerar visualizações de cartões em tempo real. Estes assuntos apresentam modos de aprendizagem e teste únicos, adaptados a conceitos matemáticos específicos, garantindo um ambiente de prática mais eficaz.'),
  ('pt', 'doc_organization_title', 'Organizar Conteúdo'),
  ('pt', 'doc_organization_desc', 'Use Pastas para agrupar Assuntos relacionados. Também pode criar Coleções para organizar Assuntos em caminhos curados.'),
  ('pt', 'doc_creation_title', 'Criar Assuntos e Cartões'),
  ('pt', 'doc_creation_desc', 'Crie os seus próprios Assuntos e adicione Flashcards visuais. Cada cartão suporta uma imagem e um ficheiro de áudio opcional para a pronúncia.'),
  ('pt', 'doc_collections_purpose_title', 'O Propósito das Coleções'),
  ('pt', 'doc_collections_purpose_desc', 'As Coleções são caminhos curados que agrupam Assuntos. Quando inicia uma sessão a partir de uma Coleção, o sistema mistura cartões de todos os assuntos incluídos para fornecer um teste abrangente e aleatório.'),
  ('pt', 'doc_card_scope_title', 'Onde Moram os Cartões'),
  ('pt', 'doc_card_scope_desc', 'Os cartões são os blocos de construção da aprendizagem e pertencem sempre a um Assunto específico. Embora possa organizar Assuntos em Pastas ou Coleções, os próprios cartões devem ser criados dentro de um Assunto.'),
  ('pt', 'doc_localization_ui_title', 'Adicionar Traduções'),
  ('pt', 'doc_localization_ui_desc', 'Para adicionar dados localizados, basta tocar no ícone do código do idioma (ex: EN, ES, FR) no cabeçalho do editor. Isto permite-lhe fornecer nomes, descrições e conteúdo de cartões específicos para cada idioma suportado. O separador "Global" serve como a reserva principal se nenhuma tradução específica for fornecida.'),
  ('pt', 'doc_localization_details_title', 'Como Funciona a Localização'),
  ('pt', 'doc_localization_details_desc', 'O idioma "Global" é a sua reserva principal—pode ser qualquer idioma que escolher. Se fornecer traduções específicas (como inglês ou espanhol), estas substituirão os dados globais apenas quando um utilizador selecionar esse idioma específico da interface.'),
  ('pt', 'doc_json_title', 'Localização JSON'),
  ('pt', 'doc_json_desc', 'Os criadores avançados podem utilizar dados JSON para fornecer nomes e descrições localizados, tornando os assuntos acessíveis em todos os idiomas suportados.'),
  ('pt', 'doc_media_title', 'Limites de Upload de Média'),
  ('pt', 'doc_media_desc', 'Para garantir uma sincronização rápida, mantenha as imagens abaixo de 5MB e os ficheiros de áudio abaixo de 10MB.'),

  ('ro', 'doc_welcome_title', 'Bun venit la Aliolo'),
  ('ro', 'doc_welcome_desc', 'Aliolo este o platformă de învățare vizuală concepută pentru a vă ajuta să stăpâniți subiecte prin carduri de memorie și testare interactivă.'),
  ('ro', 'doc_pillars_title', 'Cei 8 piloni de bază'),
  ('ro', 'doc_pillars_desc', 'Tot conținutul din Aliolo este organizat în 8 piloni fundamentali: academic și profesional, lume, natură, corp uman, științe umaniste, timp liber, inginerie și altele. Aceste categorii oferă un cadru structurat pentru toate subiectele de pe platformă.'),
  ('ro', 'doc_leaderboard_title', 'Clasament global'),
  ('ro', 'doc_leaderboard_desc', 'Concurează cu cursanți din întreaga lume! Câștigă XP completând sesiuni de carduri și urcă în clasament. Poziția ta este actualizată în timp real pe măsură ce stăpânești noi subiecte.'),
  ('ro', 'doc_friends_title', 'Prieteni și invitații'),
  ('ro', 'doc_friends_desc', 'Învățarea este mai bună împreună! Invită prieteni la Aliolo prin profilul tău. Vă puteți urmări reciproc progresul și puteți rămâne motivați văzând cine menține cea mai lungă serie.'),
  ('ro', 'doc_streaks_title', 'Sistem de serii (Streaks)'),
  ('ro', 'doc_streaks_desc', 'Consecvența este cheia! Îndeplinește-ți obiectivul zilnic în fiecare zi pentru a-ți construi seria. Nu rata nicio zi, altfel seria se va reseta.'),
  ('ro', 'doc_goals_title', 'Obiective zilnice'),
  ('ro', 'doc_goals_desc', 'Setează-ți obiectivul zilnic de completare a cardurilor în setări. Modificările aduse obiectivului tău intră în vigoare începând cu ziua următoare.'),
  ('ro', 'doc_public_title', 'Public vs Privat'),
  ('ro', 'doc_public_desc', 'Subiectele pot fi private (vizibile doar pentru tine) sau publice. Conținutul public este partajat cu întreaga comunitate Aliolo, permițând tuturor să descopere și să învețe din creațiile tale.'),
  ('ro', 'doc_sync_title', 'Sincronizare în cloud'),
  ('ro', 'doc_sync_desc', 'Progresul tău este sincronizat automat în cloud. Poți comuta între versiunile web și desktop fără a-ți pierde seria.'),
  ('ro', 'doc_feedback_title', 'Sistem de feedback'),
  ('ro', 'doc_feedback_desc', 'Ajută-ne să ne îmbunătățim! Folosește pictograma de feedback (Icons.feedback) de pe orice subiect sau dosar pentru a raporta probleme. De asemenea, poți trimite feedback general despre aplicație prin secțiunea Asistență.'),
  ('ro', 'doc_lang_title', 'Limba de învățare'),
  ('ro', 'doc_lang_desc', 'Selectează întotdeauna limba de învățare preferată în meniul de sus înainte de a selecta un subiect. Acest lucru asigură încărcarea corectă a sunetului și a traducerilor.'),
  ('ro', 'doc_filters_title', 'Căutare și filtre'),
  ('ro', 'doc_filters_desc', 'Găsește rapid conținut folosind bara de căutare. Poți filtra după grupă de vârstă (de la timpuriu la avansat) sau poți restrânge vizualizarea la colecții și dosare specifice.'),
  ('ro', 'doc_flashcards_title', 'Flashcard-uri vizuale'),
  ('ro', 'doc_flashcards_desc', 'Fiecare subiect conține un set de carduri. Deși imaginile și sunetul sunt acceptate, acestea sunt opționale – conținutul poate fi pur textual sau generat dinamic.'),
  ('ro', 'doc_study_modes_title', 'Moduri de studiu adaptative'),
  ('ro', 'doc_study_modes_desc', 'Aliolo acceptă diverse moduri de testare bazate pe conținutul tău: imagine la text, sunet la imagine și text la sunet. Această abordare multisenzorială asigură stăpânirea subiectelor din toate unghiurile.'),
  ('ro', 'doc_testing_title', 'Testare interactivă'),
  ('ro', 'doc_testing_desc', 'Provoacă-te cu întrebări cu alegere multiplă (MCQ). Aplicația va avansa automat pe măsură ce răspunzi, ajutându-te să înveți mai repede.'),
  ('ro', 'doc_autoplay_title', 'Învățare cu redare automată'),
  ('ro', 'doc_autoplay_desc', 'Aplicația poate avansa automat la următorul card după ce răspunzi. Răspunsurile corecte așteaptă 1 s, în timp ce cele incorecte așteaptă 2 s pentru a-ți permite să revizuiești.'),
  ('ro', 'doc_math_title', 'Subiecte matematice'),
  ('ro', 'doc_math_desc', 'Subiectele matematice utilizează motoare specializate pentru a genera vizualizări ale cardurilor în timp real. Aceste subiecte prezintă moduri unice de învățare și testare adaptate conceptelor matematice specifice, asigurând un mediu de practică mai eficient.'),
  ('ro', 'doc_organization_title', 'Organizarea conținutului'),
  ('ro', 'doc_organization_desc', 'Folosește dosare pentru a grupa subiectele înrudite. De asemenea, poți crea colecții pentru a organiza subiectele în căi curatoriate.'),
  ('ro', 'doc_creation_title', 'Crearea subiectelor și cardurilor'),
  ('ro', 'doc_creation_desc', 'Creează-ți propriile subiecte și adaugă flashcard-uri vizuale. Fiecare card acceptă o imagine și un fișier audio opțional pentru pronunție.'),
  ('ro', 'doc_collections_purpose_title', 'Scopul colecțiilor'),
  ('ro', 'doc_collections_purpose_desc', 'Colecțiile sunt căi curatoriate care grupează subiectele. Când începi o sesiune dintr-o colecție, sistemul amestecă carduri din toate subiectele incluse pentru a oferi un test cuprinzător, randomizat.'),
  ('ro', 'doc_card_scope_title', 'Unde trăiesc cardurile'),
  ('ro', 'doc_card_scope_desc', 'Cardurile sunt elementele de bază ale învățării și aparțin întotdeauna unui anumit subiect. Deși poți organiza subiectele în dosare sau colecții, cardurile în sine trebuie create în cadrul unui subiect.'),
  ('ro', 'doc_localization_ui_title', 'Adăugarea traducerilor'),
  ('ro', 'doc_localization_ui_desc', 'Pentru a adăuga date localizate, atinge pur și simplu pictograma codului de limbă (de exemplu, EN, ES, FR) în antetul editorului. Acest lucru îți permite să furnizezi nume, descrieri și conținut specific cardurilor pentru fiecare limbă acceptată. Fila „Global” servește drept rezervă principală dacă nu este furnizată nicio traducere specifică.'),
  ('ro', 'doc_localization_details_title', 'Cum funcționează localizarea'),
  ('ro', 'doc_localization_details_desc', 'Limba „Global” este rezerva ta principală – poate fi orice limbă alegi. Dacă furnizezi traduceri specifice (cum ar fi engleza sau spaniola), acestea vor suprascrie datele globale numai atunci când un utilizator selectează acea limbă specifică a interfeței.'),
  ('ro', 'doc_json_title', 'Localizare JSON'),
  ('ro', 'doc_json_desc', 'Creatorii avansați pot folosi datele JSON pentru a furniza nume și descrieri localizate, făcând subiectele accesibile în toate limbile acceptate.'),
  ('ro', 'doc_media_title', 'Limite de încărcare media'),
  ('ro', 'doc_media_desc', 'Pentru a asigura o sincronizare rapidă, păstrați imaginile sub 5 MB și fișierele audio sub 10 MB.'),

  ('sk', 'doc_welcome_title', 'Vitajte v Aliolo'),
  ('sk', 'doc_welcome_desc', 'Aliolo je vizuálna vzdelávacia platforma navrhnutá tak, aby vám pomohla ovládať predmety prostredníctvím kartičiek a interaktívneho testovania.'),
  ('sk', 'doc_pillars_title', '8 hlavných pilierov'),
  ('sk', 'doc_pillars_desc', 'Všetok obsah v Aliolo je rozdelený do 8 základných pilierov: akademický a profesionálny, svet, príroda, ľudské telo, humanitné vedy, voľný čas, inžinierstvo a ostatné. Tieto kategórie poskytujú štruktúrovaný rámec pre všetky predmety v rámci platformy.'),
  ('sk', 'doc_leaderboard_title', 'Globálny rebríček'),
  ('sk', 'doc_leaderboard_desc', 'Súťažte so študentmi z celého sveta! Získajte XP dokončením lekcií s kartami a stúpajte v rebríčku. Vaša pozícia sa aktualizuje v reálnom čase, keď ovládnete nové predmety.'),
  ('sk', 'doc_friends_title', 'Priatelia a pozvánky'),
  ('sk', 'doc_friends_desc', 'Učenie je lepšie spoločne! Pozvite priateľov do Aliolo prostredníctvom svojho profilu. Môžete sledovať pokrok jeden druhého a zostať motivovaní tým, že uvidíte, kto si udržuje najdlhšiu sériu.'),
  ('sk', 'doc_streaks_title', 'Systém sérií (Streaks)'),
  ('sk', 'doc_streaks_desc', 'Dôslednosť je kľúčová! Plňte svoj denný cieľ každý deň, aby ste si vybudovali sériu. Nevynechajte ani deň, inak sa séria vynuluje.'),
  ('sk', 'doc_goals_title', 'Denné ciele'),
  ('sk', 'doc_goals_desc', 'V nastaveniach si určte svoj denný cieľ dokončenia kariet. Zmeny v cieli sa prejavia až od nasledujúceho dňa.'),
  ('sk', 'doc_public_title', 'Verejné vs súkromné'),
  ('sk', 'doc_public_desc', 'Predmety môžu byť súkromné (viditeľné iba pre vás) alebo verejné. Verejný obsah je zdieľaný s celou komunitou Aliolo, čo umožňuje každému objavovať a učiť sa z vašich výtvorov.'),
  ('sk', 'doc_sync_title', 'Synchronizácia s cloudom'),
  ('sk', 'doc_sync_desc', 'Váš pokrok sa automaticky synchronizuje s cloudom. Môžete prepínať medzi webovou a desktopovou verziou bez straty série.'),
  ('sk', 'doc_feedback_title', 'Systém spätnej väzby'),
  ('sk', 'doc_feedback_desc', 'Pomôžte nám sa zlepšovať! Pomocou ikony spätnej väzby (Icons.feedback) na akomkoľvek predmete alebo priečinku nahláste problémy. Môžete tiež poslať všeobecnú spätnú väzbu k aplikácii prostredníctvom sekcie Podpora.'),
  ('sk', 'doc_lang_title', 'Jazyk učenia'),
  ('sk', 'doc_lang_desc', 'Pred výberom predmetu si v hornom menu vždy vyberte preferovaný jazyk učenia. Tým sa zabezpečí načítanie správneho audia a prekladov.'),
  ('sk', 'doc_filters_title', 'Hľadanie a filtre'),
  ('sk', 'doc_filters_desc', 'Rýchlo nájdite obsah pomocou vyhľadávacieho panela. Môžete filtrovať podľa vekovej skupiny (od ranej po pokročilú) alebo zúžiť zobrazenie na konkrétne zbierky a priečinky.'),
  ('sk', 'doc_flashcards_title', 'Vizuálne kartičky'),
  ('sk', 'doc_flashcards_desc', 'Každý predmet obsahuje sústavu kariet. Aj keď sú obrázky a audio podporované, sú voliteľné – obsah môže byť čisto textový alebo dynamicky generovaný.'),
  ('sk', 'doc_study_modes_title', 'Adaptívne študijné režimy'),
  ('sk', 'doc_study_modes_desc', 'Aliolo podporuje rôzne režimy testovania na základe vášho obsahu: obrázok na text, audio na obrázok a text na audio. Tento multizmyslový prístup zabezpečí, že predmety ovládnete z každého uhla.'),
  ('sk', 'doc_testing_title', 'Interaktívne testovanie'),
  ('sk', 'doc_testing_desc', 'Vyzvite sa otázkami s výberom odpovede (MCQ). Aplikácia bude po vašej odpovedi automaticky pokračovať, čo vám pomôže učiť sa rýchlejšie.'),
  ('sk', 'doc_autoplay_title', 'Automatické učenie'),
  ('sk', 'doc_autoplay_desc', 'Aplikácia môže po vašej odpovedi automaticky prejsť na ďalšiu kartu. Správne odpovede čakajú 1 s, zatiaľ čo nesprávne 2 s, aby ste si ich mohli prezrieť.'),
  ('sk', 'doc_math_title', 'Matematické predmety'),
  ('sk', 'doc_math_desc', 'Matematické predmety využívajú špecializované enginy na generovanie vizualizácií kariet v reálnom čase. Tieto predmety obsahujú jedinečné režimy učenia a testovania prispôsobené konkrétnym matematickým konceptom, čo zabezpečuje efektívnejšie prostredie na precvičovanie.'),
  ('sk', 'doc_organization_title', 'Organizácia obsahu'),
  ('sk', 'doc_organization_desc', 'Pomocou priečinkov môžete zoskupovať súvisiace predmety. Môžete tiež vytvárať zbierky a organizovať predmety do vybraných ciest.'),
  ('sk', 'doc_creation_title', 'Vytváranie predmetov a kariet'),
  ('sk', 'doc_creation_desc', 'Vytvárajte vlastné predmety a pridávajte vizuálne kartičky. Každá karta podporuje obrázok a voliteľný audio súbor pre výslovnosť.'),
  ('sk', 'doc_collections_purpose_title', 'Účel zbierok'),
  ('sk', 'doc_collections_purpose_desc', 'Zbierky sú vybrané cesty, ktoré zoskupujú predmety. Keď spustíte lekciu zo zbierky, systém namieša karty zo všetkých zahrnutých predmetov, aby poskytol náhodný a komplexný test.'),
  ('sk', 'doc_card_scope_title', 'Kde karty žijú'),
  ('sk', 'doc_card_scope_desc', 'Karty sú základnými stavebnými kameňmi učenia a vždy patria ku konkrétnemu predmetu. Aj keď môžete predmety organizovať do priečinkov alebo zbierok, samotné karty musia byť vytvorené v rámci predmetu.'),
  ('sk', 'doc_localization_ui_title', 'Pridávanie prekladov'),
  ('sk', 'doc_localization_ui_desc', 'Ak chcete pridať lokalizované údaje, jednoducho klepnite na ikonu kódu jazyka (napr. EN, ES, FR) v záhlaví editora. To vám umožní zadať konkrétne názvy, popisy a obsah kariet pre každý podporovaný jazyk. Karta „Globálne“ slúži ako primárna záloha, ak nie je k dispozícii žiadny konkrétny preklad.'),
  ('sk', 'doc_localization_details_title', 'Ako funguje lokalizácia'),
  ('sk', 'doc_localization_details_desc', '„Globálny“ jazyk je vaša primárna záloha – môže to byť akýkoľvek jazyk, ktorý si vyberiete. Ak poskytnete konkrétne preklady (napríklad angličtinu alebo španielčinu), prepíšu globálne údaje len vtedy, keď si používateľ zvolí tento konkrétny jazyk používateľského rozhrania.'),
  ('sk', 'doc_json_title', 'JSON lokalizácia'),
  ('sk', 'doc_json_desc', 'Pokročilí tvorcovia môžu pomocou údajov JSON poskytovať lokalizované názvy a popisy, vďaka čomu sú predmety prístupné vo všetkých podporovaných jazykoch.'),
  ('sk', 'doc_media_title', 'Limity pre nahrávanie médií'),
  ('sk', 'doc_media_desc', 'Pro zabezpečenie rýchlej synchronizácie udržujte obrázky pod 5 MB a audio súbory pod 10 MB.'),

  ('sl', 'doc_welcome_title', 'Dobrodošli v Aliolo'),
  ('sl', 'doc_welcome_desc', 'Aliolo je platforma za vizualno učenje, zasnovana tako, da vam pomaga usvojiti predmete s pomočjo kartic in interaktivnega testiranja.'),
  ('sl', 'doc_pillars_title', '8 temeljnih stebrov'),
  ('sl', 'doc_pillars_desc', 'Vsa vsebina v Aliolu je organizirana v 8 temeljnih stebrov: akademsko in poklicno, svet, narava, človeško telo, humanistika, prosti čas, inženirstvo in drugo. Te kategorije zagotavljajo strukturiran okvir za vse predmete na platformi.'),
  ('sl', 'doc_leaderboard_title', 'Globalna lestvica'),
  ('sl', 'doc_leaderboard_desc', 'Tekmujte z učenci po vsem svetu! Prislužite si XP z dokončanjem sej s karticami in se povzpnite na lestvici. Vaš položaj se posodablja v realnem času, ko osvajate nove predmete.'),
  ('sl', 'doc_friends_title', 'Prijatelji in povabila'),
  ('sl', 'doc_friends_desc', 'Učenje je boljše v dvoje! Povabite prijatelje v Aliolo prek svojega profila. Lahko spremljate napredek drug drugega in ostanete motivirani tako, da vidite, kdo ohranja najdaljši niz.'),
  ('sl', 'doc_streaks_title', 'Sistem nizov (Streaks)'),
  ('sl', 'doc_streaks_desc', 'Doslednost je ključna! Vsak dan izpolnite svoj dnevni cilj, da zgradite svoj niz. Ne zamudite niti enega dneva, sicer se bo niz ponastavil.'),
  ('sl', 'doc_goals_title', 'Dnevni cilji'),
  ('sl', 'doc_goals_desc', 'V nastavitvah določite svoj dnevni cilj dokončanja kartic. Spremembe cilja začnejo veljati naslednji dan.'),
  ('sl', 'doc_public_title', 'Javno proti zasebnemu'),
  ('sl', 'doc_public_desc', 'Predmeti so lahko zasebni (vidni samo vam) ali javni. Javna vsebina se deli s celotno skupnostjo Aliolo, kar vsem omogoča odkrivanje in učenje iz vaših stvaritev.'),
  ('sl', 'doc_sync_title', 'Sinhronizacija v oblaku'),
  ('sl', 'doc_sync_desc', 'Vaš napredek se samodejno sinhronizira z oblakom. Med spletno in namizno različico lahko preklapljate, ne da bi izgubili svoj niz.'),
  ('sl', 'doc_feedback_title', 'Sistem povratnih informacij'),
  ('sl', 'doc_feedback_desc', 'Pomagajte nam izboljšati! Uporabite ikono za povratne informacije (Icons.feedback) na katerem koli predmetu ali mapi, da prijavite težave. Prek razdelka Podpora lahko pošljete tudi splošne povratne informacije o aplikaciji.'),
  ('sl', 'doc_lang_title', 'Jezik učenja'),
  ('sl', 'doc_lang_desc', 'Pred izbiro predmeta v zgornjem meniju vedno izberite želeni jezik učenja. To zagotavlja nalaganje pravilnega zvoka in prevodov.'),
  ('sl', 'doc_filters_title', 'Iskanje in filtri'),
  ('sl', 'doc_filters_desc', 'Hitro poiščite vsebino z iskalno vrstico. Filtrirate lahko po starostni skupini (od zgodnje do napredne) ali zožite pogled na določene zbirke in mape.'),
  ('sl', 'doc_flashcards_title', 'Vizualne kartice'),
  ('sl', 'doc_flashcards_desc', 'Vsak predmet vsebuje nabor kartic. Čeprav so slike in zvok podprti, so neobvezni – vsebina je lahko zgolj besedilna ali dinamično generirana.'),
  ('sl', 'doc_study_modes_title', 'Prilagodljivi načini učenja'),
  ('sl', 'doc_study_modes_desc', 'Aliolo podpira različne načine testiranja glede na vašo vsebino: slika v besedilo, zvok v sliko in besedilo v zvok. Ta veččutni pristop zagotavlja, da predmete usvojite z vseh zornih kotov.'),
  ('sl', 'doc_testing_title', 'Interaktivno testiranje'),
  ('sl', 'doc_testing_desc', 'Preizkusite se z vprašanji z več izbirami (MCQ). Aplikacija bo med odgovarjanjem samodejno napredovala, kar vam bo pomagalo do hitrejšega učenja.'),
  ('sl', 'doc_autoplay_title', 'Samodejno učenje'),
  ('sl', 'doc_autoplay_desc', 'Aplikacija lahko po vašem odgovoru samodejno preklopi na naslednjo kartico. Pravilni odgovori počakajo 1 s, napačni pa 2 s, da si jih lahko ogledate.'),
  ('sl', 'doc_math_title', 'Matematični predmeti'),
  ('sl', 'doc_math_desc', 'Matematični predmeti uporabljajo specializirane mehanizme za generiranje vizualizacij kartic v realnem času. Ti predmeti imajo edinstvene načine učenja in testiranja, prilagojene specifičnim matematičnim konceptom, kar zagotavlja učinkovitejše okolje za vadbo.'),
  ('sl', 'doc_organization_title', 'Organiziranje vsebine'),
  ('sl', 'doc_organization_desc', 'Uporabite mape za združevanje sorodnih predmetov. Ustvarite lahko tudi zbirke za organiziranje predmetov v izbrane poti.'),
  ('sl', 'doc_creation_title', 'Ustvarjanje predmetov in kartic'),
  ('sl', 'doc_creation_desc', 'Ustvarite lastne predmete in dodajte vizualne kartice. Vsaka kartica podpira sliko in neobvezno zvočno datoteko za izgovorjavo.'),
  ('sl', 'doc_collections_purpose_title', 'Namen zbirk'),
  ('sl', 'doc_collections_purpose_desc', 'Zbirke so izbrane poti, ki združujejo predmete. Ko začnete sejo iz zbirke, sistem pomeša kartice iz vseh vključenih predmetov, da zagotovi naključen, celovit preizkus.'),
  ('sl', 'doc_card_scope_title', 'Kje živijo kartice'),
  ('sl', 'doc_card_scope_desc', 'Kartice so gradniki učenja in vedno pripadajo določenemu predmetu. Čeprav lahko predmete organizirate v mape ali zbirke, morajo biti kartice same ustvarjene znotraj predmeta.'),
  ('sl', 'doc_localization_ui_title', 'Dodajanje prevodov'),
  ('sl', 'doc_localization_ui_desc', 'Če želite dodati lokalizirane podatke, se v glavi urejevalnika preprosto dotaknite ikone kode jezika (npr. EN, ES, FR). To vam omogoča, da vnesete specifična imena, opise in vsebino kartic za vsak podprt jezik. Zavihek »Globalno« služi kot primarna rezerva, če ni na voljo nobenega specifičnega prevoda.'),
  ('sl', 'doc_localization_details_title', 'Kako deluje lokalizacija'),
  ('sl', 'doc_localization_details_desc', '»Globalni« jezik je vaša primarna rezerva – to je lahko kateri koli jezik po vaši izbiri. Če vnesete specifične prevode (npr. angleščino ali španščino), bodo ti preglasili globalne podatke le, ko uporabnik izbere ta specifični jezik vmesnika.'),
  ('sl', 'doc_json_title', 'JSON lokalizacija'),
  ('sl', 'doc_json_desc', 'Napredni ustvarjalci lahko uporabijo podatke JSON za vnos lokaliziranih imen in opisov, s čimer postanejo predmeti dostopni v vseh podprtih jezikih.'),
  ('sl', 'doc_media_title', 'Omejitve pri nalaganju medijev'),
  ('sl', 'doc_media_desc', 'Za zagotovitev hitre sinhronizacije naj bodo slike manjše od 5 MB, zvočne datoteke pa manjše od 10 MB.'),

  ('fi', 'doc_welcome_title', 'Tervetuloa Alioloon'),
  ('fi', 'doc_welcome_desc', 'Aliolo on visuaalinen oppimisalusta, joka on suunniteltu auttamaan sinua hallitsemaan aiheita muistikorttien ja interaktiivisen testauksen avulla.'),
  ('fi', 'doc_pillars_title', '8 ydinpilaria'),
  ('fi', 'doc_pillars_desc', 'Kaikki Aliolon sisältö on järjestetty 8 peruspilariin: akateeminen ja ammatillinen, maailma, luonto, ihmiskeho, humanistiset tieteet, vapaa-aika, tekniikka ja muut. Nämä kategoriat tarjoavat jäsennellyn kehyksen kaikille alustan aiheille.'),
  ('fi', 'doc_leaderboard_title', 'Globaali tulostaulu'),
  ('fi', 'doc_leaderboard_desc', 'Kilpaile oppijoiden kanssa ympäri maailmaa! Ansaitse XP-pisteitä suorittamalla korttisessioita ja nouse sijoituksissa. Sijaintisi päivittyy reaaliajassa, kun hallitset uusia aiheita.'),
  ('fi', 'doc_friends_title', 'Ystävät ja kutsut'),
  ('fi', 'doc_friends_desc', 'Oppiminen on parempaa yhdessä! Kutsu ystäviä Alioloon profiilisi kautta. Voitte seurata toistenne edistymistä ja pysyä motivoituneina näkemällä, kuka ylläpitää pisintä putkea.'),
  ('fi', 'doc_streaks_title', 'Putkijärjestelmä (Streaks)'),
  ('fi', 'doc_streaks_desc', 'Johdonmukaisuus on avain! Saavuta päivittäinen tavoitteesi joka päivä kasvattaaksesi putkeasi. Älä jätä päivääkään väliin, muuten putki nollautuu.'),
  ('fi', 'doc_goals_title', 'Päivittäiset tavoitteet'),
  ('fi', 'doc_goals_desc', 'Aseta päivittäinen korttien suoritustavoitteesi asetuksista. Tavoitteen muutokset astuvat voimaan seuraavasta päivästä alkaen.'),
  ('fi', 'doc_public_title', 'Julkinen vs. yksityinen'),
  ('fi', 'doc_public_desc', 'Aiheet voivat olla yksityisiä (näkyvissä vain sinulle) tai julkisia. Julkinen sisältö jaetaan koko Aliolo-yhteisölle, jolloin kaikki voivat löytää luomuksesi ja oppia niistä.'),
  ('fi', 'doc_sync_title', 'Pilvisynkronointi'),
  ('fi', 'doc_sync_desc', 'Edistymisesi synkronoidaan automaattisesti pilveen. Voit vaihtaa verkko- ja työpöytäversioiden välillä menettämättä putkeasi.'),
  ('fi', 'doc_feedback_title', 'Palautejärjestelmä'),
  ('fi', 'doc_feedback_desc', 'Auta meitä parantamaan! Käytä palautekuvaketta (Icons.feedback) missä tahansa aiheessa tai kansiossa ilmoittaaksesi ongelmista. Voit myös lähettää yleistä sovelluspalautetta tuki-osion kautta.'),
  ('fi', 'doc_lang_title', 'Oppimiskieli'),
  ('fi', 'doc_lang_desc', 'Valitse aina haluamasi oppimiskieli ylävalikosta ennen aiheen valitsemista. Tämä varmistaa, että oikeat äänet ja käännökset ladataan.'),
  ('fi', 'doc_filters_title', 'Haku ja suodattimet'),
  ('fi', 'doc_filters_desc', 'Löydä sisältöä nopeasti hakupalkin avulla. Voit suodattaa ikäryhmän mukaan (varhaisesta edistyneeseen) tai rajata näkymän tiettyihin kokoelmiin ja kansioihin.'),
  ('fi', 'doc_flashcards_title', 'Visuaaliset muistikortit'),
  ('fi', 'doc_flashcards_desc', 'Jokainen aihe sisältää sarjan kortteja. Vaikka kuvia ja ääntä tuetaan, ne ovat valinnaisia – sisältö voi olla puhtaasti tekstuaalista tai dynaamisesti luotua.'),
  ('fi', 'doc_study_modes_title', 'Adaptiiviset opiskelutilat'),
  ('fi', 'doc_study_modes_desc', 'Aliolo tukee erilaisia testaustiloja sisällöstäsi riippuen: kuvasta tekstiksi, äänestä kuvaksi ja tekstistä äänelle. Tämä moniaistinen lähestymistapa varmistaa, että hallitset aiheet kaikista näkökulmista.'),
  ('fi', 'doc_testing_title', 'Interaktiivinen testaus'),
  ('fi', 'doc_testing_desc', 'Haasta itsesi monivalintakysymyksillä (MCQ). Sovellus etenee automaattisesti vastatessasi, mikä auttaa sinua oppimaan nopeammin.'),
  ('fi', 'doc_autoplay_title', 'Automaattinen oppiminen'),
  ('fi', 'doc_autoplay_desc', 'Sovellus voi siirtyä automaattisesti seuraavaan korttiin vastauksesi jälkeen. Oikeat vastaukset odottavat 1 s, kun taas väärät odottavat 2 s, jotta ehdit tarkistaa ne.'),
  ('fi', 'doc_math_title', 'Matemaattiset aiheet'),
  ('fi', 'doc_math_desc', 'Matemaattisissa aiheissa käytetään erikoistuneita moottoreita korttivizualisointien luomiseen reaaliajassa. Näissä aiheissa on ainutlaatuisia oppimis- ja testaustiloja, jotka on räätälöity tiettyihin matemaattisiin käsitteisiin, mikä varmistaa tehokkaamman harjoitteluympäristön.'),
  ('fi', 'doc_organization_title', 'Sisällön järjestäminen'),
  ('fi', 'doc_organization_desc', 'Käytä kansioita aiheeseen liittyvien aiheiden ryhmittelemiseen. Voit myös luoda kokoelmia järjestääksesi aiheet kuratoiduiksi poluiksi.'),
  ('fi', 'doc_creation_title', 'Aiheiden ja korttien luominen'),
  ('fi', 'doc_creation_desc', 'Luo omia aiheita ja lisää visuaalisia muistikortteja. Jokainen kortti tukee kuvaa ja valinnaista äänitiedostoa ääntämistä varten.'),
  ('fi', 'doc_collections_purpose_title', 'Kokoelmien tarkoitus'),
  ('fi', 'doc_collections_purpose_desc', 'Kokoelmat ovat kuratoituja polkuja, jotka ryhmittelevät aiheita. Kun aloitat istunnon kokoelmasta, järjestelmä sekoittaa kortteja kaikista mukana olevista aiheista tarjotakseen satunnaistetun, kattavan testin.'),
  ('fi', 'doc_card_scope_title', 'Missä kortit asuvat'),
  ('fi', 'doc_card_scope_desc', 'Kortit ovat oppimisen rakennuspalikoita ja kuuluvat aina tiettyyn aiheeseen. Vaikka voit järjestää aiheita kansioihin tai kokoelmiin, itse kortit on luotava aiheen sisällä.'),
  ('fi', 'doc_localization_ui_title', 'Käännösten lisääminen'),
  ('fi', 'doc_localization_ui_desc', 'Lisää lokalisoitua dataa napauttamalla kielikoodikuvaketta (esim. EN, ES, FR) editorin otsikossa. Tämän avulla voit antaa tietyt nimet, kuvaukset ja korttien sisällön jokaiselle tuetulle kielelle. Global-välilehti toimii ensisijaisena varana, jos erityistä käännöstä ei ole annettu.'),
  ('fi', 'doc_localization_details_title', 'Kuinka lokalisointi toimii'),
  ('fi', 'doc_localization_details_desc', 'Global-kieli on ensisijainen varasi – se voi olla mikä tahansa valitsemasi kieli. Jos annat erityisiä käännöksiä (kuten englanti tai espanja), ne korvaavat Global-tiedot vain, kun käyttäjä valitsee kyseisen UI-kielen.'),
  ('fi', 'doc_json_title', 'JSON-lokalisointi'),
  ('fi', 'doc_json_desc', 'Edistyneet luojat voivat käyttää JSON-dataa lokalisoitujen nimien ja kuvausten tarjoamiseen, mikä tekee aiheista saavutettavia kaikilla tuetuilla kielillä.'),
  ('fi', 'doc_media_title', 'Median latausrajat'),
  ('fi', 'doc_media_desc', 'Nopean synkronoinnin varmistamiseksi pidä kuvat alle 5 megatavussa ja äänitiedostot alle 10 megatavussa.'),

  ('sv', 'doc_welcome_title', 'Välkommen till Aliolo'),
  ('sv', 'doc_welcome_desc', 'Aliolo är en visuell lärplattform designad för att hjälpa dig att bemästra ämnen genom flashcards och interaktiv testning.'),
  ('sv', 'doc_pillars_title', 'De 8 kärnpelarna'),
  ('sv', 'doc_pillars_desc', 'Allt innehåll i Aliolo är organiserat i 8 grundläggande pelare: Akademisk & Professionell, Världen, Natur, Människokroppen, Humaniora, Fritid, Teknik och Övrigt. Dessa kategorier ger ett strukturerat ramverk för alla ämnen på plattformen.'),
  ('sv', 'doc_leaderboard_title', 'Global topplista'),
  ('sv', 'doc_leaderboard_desc', 'Tävla med elever över hela världen! Tjäna XP genom att slutföra kortsessioner och klättra i rankingen. Din position uppdateras i realtid allt eftersom du bemästrar nya ämnen.'),
  ('sv', 'doc_friends_title', 'Vänner & Inbjudningar'),
  ('sv', 'doc_friends_desc', 'Lärande är bättre tillsammans! Bjuda in vänner till Aliolo via din profil. Ni kan följa varandras framsteg och hålla motivationen uppe genom att se vem som har den längsta streaken.'),
  ('sv', 'doc_streaks_title', 'Streak-system'),
  ('sv', 'doc_streaks_desc', 'Konsistens är nyckeln! Uppnå ditt dagliga mål varje dag för att bygga din streak. Missa inte en dag, annars nollställs streaken.'),
  ('sv', 'doc_goals_title', 'Dagliga mål'),
  ('sv', 'doc_goals_desc', 'Ställ in ditt dagliga mål för kortgenomförande i inställningarna. Ändringar av ditt mål träder i kraft från och med nästa dag.'),
  ('sv', 'doc_public_title', 'Offentlig vs Privat'),
  ('sv', 'doc_public_desc', 'Ämnen kan vara privata (synliga endast för dig) eller offentliga. Offentligt innehåll delas med hela Aliolo-communityn, vilket gör att alla kan upptäcka och lära sig av dina skapelser.'),
  ('sv', 'doc_sync_title', 'Molnsynkronisering'),
  ('sv', 'doc_sync_desc', 'Dina framsteg synkroniseras automatiskt till molnet. Du kan växla mellan webb- och skrivbordsversioner utan att förlora din streak.'),
  ('sv', 'doc_feedback_title', 'Feedback-system'),
  ('sv', 'doc_feedback_desc', 'Hjälp oss att bli bättre! Använd feedback-ikonen (Icons.feedback) på ett ämne eller en mapp för att rapportera problem. Du kan också skicka allmän feedback om appen via supportsektionen.'),
  ('sv', 'doc_lang_title', 'Lärspråk'),
  ('sv', 'doc_lang_desc', 'Välj alltid ditt föredragna lärspråk i toppmenyn innan du väljer ett ämne. Detta säkerställer att rätt ljud och översättningar laddas.'),
  ('sv', 'doc_filters_title', 'Sök & Filter'),
  ('sv', 'doc_filters_desc', 'Hitta snabbt innehåll med hjälp av sökfältet. Du kan filtrera efter åldersgrupp (från tidig till avancerad) eller begränsa din vy till specifika samlingar och mappar.'),
  ('sv', 'doc_flashcards_title', 'Visuella flashcards'),
  ('sv', 'doc_flashcards_desc', 'Varje ämne innehåller en uppsättning kort. Även om bilder och ljud stöds är de valfria – innehållet kan vara rent textbaserat eller genereras dynamiskt.'),
  ('sv', 'doc_study_modes_title', 'Adaptiva studielägen'),
  ('sv', 'doc_study_modes_desc', 'Aliolo stöder olika testlägen baserat på ditt innehåll: Bild-till-text, Ljud-till-bild och Text-to-Audio. Detta multisensoriska tillvägagångssätt säkerställer att du bemästrar ämnen från alla vinklar.'),
  ('sv', 'doc_testing_title', 'Interaktiv testning'),
  ('sv', 'doc_testing_desc', 'Utmana dig själv med flervalsfrågor (MCQ). Appen går automatiskt vidare när du svarar, vilket hjälper dig att lära dig snabbare.'),
  ('sv', 'doc_autoplay_title', 'Lärande med automatisk uppspelning'),
  ('sv', 'doc_autoplay_desc', 'Appen kan automatiskt gå vidare till nästa kort efter att du svarat. Rätta svar väntar 1 sek, medan felaktiga väntar 2 sek för att låta dig granska.'),
  ('sv', 'doc_math_title', 'Matematiska ämnen'),
  ('sv', 'doc_math_desc', 'Matematiska ämnen använder specialiserade motorer för att generera kortvisualiseringer i realtid. Dessa ämnen har unika lär- och testlägen skräddarsydda för specifika matematiska koncept, vilket säkerställer en mer effektiv övningsmiljö.'),
  ('sv', 'doc_organization_title', 'Organisera innehåll'),
  ('sv', 'doc_organization_desc', 'Använd mappar för att gruppera relaterade ämnen. Du kan också skapa samlingar för att organisera ämnen i kurerade vägar.'),
  ('sv', 'doc_creation_title', 'Skapa ämnen & kort'),
  ('sv', 'doc_creation_desc', 'Skapa dina egna ämnen och lägg till visuella flashcards. Varje kort stöder en bild och en valfri ljudfil för uttal.'),
  ('sv', 'sv', 'doc_collections_purpose_title', 'Syftet med samlingar'),
  ('sv', 'doc_collections_purpose_desc', 'Samlingar är kurerade vägar som grupperar ämnen. När du startar en session från en samling blandar systemet kort från alla inkluderade ämnen för att ge ett randomiserat, omfattande test.'),
  ('sv', 'doc_card_scope_title', 'Var korten bor'),
  ('sv', 'doc_card_scope_desc', 'Korten är byggstenarna i lärandet och tillhör alltid ett specifikt ämne. Även om du kan organisera ämnen i mappar eller samlingar, måste själva korten skapas inom ett ämne.'),
  ('sv', 'doc_localization_ui_title', 'Lägga till översättningar'),
  ('sv', 'doc_localization_ui_desc', 'För att lägga till lokaliserad data, tryck helt enkelt på språkkodikonen (t.ex. EN, ES, FR) i redigerarens rubrik. Detta gör att du kan ange specifika namn, beskrivningar och kortinnehåll för varje språk som stöds. Fliken "Global" fungerar som den primära reserven om ingen specifik översättning tillhandahålls.'),
  ('sv', 'doc_localization_details_title', 'Hur lokalisering fungerar'),
  ('sv', 'doc_localization_details_desc', 'Språket "Global" är din primära reserv – det kan vara vilket språk du vill. Om du tillhandahåller specifika översättningar (som engelska eller spanska) kommer de att åsidosätta de globala data endast när en användare väljer det specifika UI-språket.'),
  ('sv', 'doc_json_title', 'JSON-lokalisering'),
  ('sv', 'doc_json_desc', 'Avancerade skapare kan använda JSON-data för att tillhandahålla lokaliserade namn och beskrivningar, vilket gör ämnen tillgängliga på alla språk som stöds.'),
  ('sv', 'doc_media_title', 'Uppladdningsgränser för media'),
  ('sv', 'doc_media_desc', 'För att säkerställa snabb synkronisering, håll bilder under 5 MB och ljudfiler under 10 MB.'),

  ('tl', 'doc_welcome_title', 'Maligayang pagdating sa Aliolo'),
  ('tl', 'doc_welcome_desc', 'Ang Aliolo ay isang visual learning platform na idinisenyo upang tulungan kang masterin ang mga paksa sa pamamagitan ng mga flashcard at interactive na pagsubok.'),
  ('tl', 'doc_pillars_title', 'Ang 8 Pangunahing Haligi'),
  ('tl', 'doc_pillars_desc', 'Ang lahat ng nilalaman sa Aliolo ay nakaorganisa sa 8 pundamental na haligi: Akademiko at Propesyonal, Mundo, Kalikasan, Katawan ng Tao, Humanidades, Paglilibang, Inhenyeriya, at Iba pa. Ang mga kategoryang ito ay nagbibigay ng estrukturadong balangkas para sa lahat ng paksa sa buong platform.'),
  ('tl', 'doc_leaderboard_title', 'Global na Leaderboard'),
  ('tl', 'doc_leaderboard_desc', 'Makipagkumpitensya sa mga mag-aaral sa buong mundo! Kumita ng XP sa pamamagitan ng pagkumpleto ng mga sesyon ng card at umakyat sa mga ranggo. Ang iyong posisyon ay ina-update nang real-time habang namamanata ka ng mga bagong paksa.'),
  ('tl', 'doc_friends_title', 'Mga Kaibigan at Imbitasyon'),
  ('tl', 'doc_friends_desc', 'Mas masaya ang pag-aaral nang magkakasama! Mag-imbita ng mga kaibigan sa Aliolo sa pamamagitan ng iyong profile. Maaari ninyong subaybayan ang pag-unlad ng isa''t isa at manatiling motivated sa pamamagitan ng pagtingin kung sino ang nagpapanatili ng pinakamahabang streak.'),
  ('tl', 'doc_streaks_title', 'Sistema ng Streak'),
  ('tl', 'doc_streaks_desc', 'Consistency ang susi! Kumpletuhin ang iyong pang-araw-araw na layunin bawat araw upang mabuo ang iyong streak. Huwag palampasin ang isang araw, kung hindi ay magre-reset ang streak.'),
  ('tl', 'doc_goals_title', 'Mga Pang-araw-araw na Layunin'),
  ('tl', 'doc_goals_desc', 'Itakda ang iyong pang-araw-araw na target sa pagkumpleto ng card sa mga setting. Ang mga pagbabago sa iyong layunin ay magkakabisa simula sa susunod na araw.'),
  ('tl', 'doc_public_title', 'Publiko vs Pribado'),
  ('tl', 'doc_public_desc', 'Ang mga paksa ay maaaring pribado (ikaw lang ang nakakakita) o publiko. Ang pampublikong nilalaman ay ibinabahagi sa buong komunidad ng Aliolo, na nagbibigay-daan sa lahat na matuklasan at matuto mula sa iyong mga likha.'),
  ('tl', 'doc_sync_title', 'Cloud Sync'),
  ('tl', 'doc_sync_desc', 'Awtomatikong sina-sync ang iyong pag-unlad sa cloud. Maaari kang lumipat sa pagitan ng mga bersyon ng web at desktop nang hindi nawawala ang iyong streak.'),
  ('tl', 'doc_feedback_title', 'Sistema ng Feedback'),
  ('tl', 'doc_feedback_desc', 'Tulungan kaming mapabuti! Gamitin ang icon ng feedback (Icons.feedback) sa anumang Paksa o Folder upang mag-ulat ng mga isyu. Maaari ka ring magpadala ng pangkalahatang feedback sa app sa pamamagitan ng seksyon ng Suporta.'),
  ('tl', 'doc_lang_title', 'Wika ng Pag-aaral'),
  ('tl', 'doc_lang_desc', 'Palaging piliin ang iyong gustong wika ng pag-aaral sa itaas na menu bago pumili ng paksa. Tinitiyak nito na ang tamang audio at mga pagsasalin ay nalo-load.'),
  ('tl', 'doc_filters_title', 'Paghahanap at Mga Filter'),
  ('tl', 'doc_filters_desc', 'Mabilis na makahanap ng nilalaman gamit ang search bar. Maaari kang mag-filter ayon sa Age Group (Early hanggang Advanced) o pakitid ang iyong pananaw sa mga partikular na Koleksyon at Folder.'),
  ('tl', 'doc_flashcards_title', 'Mga Visual Flashcard'),
  ('tl', 'doc_flashcards_desc', 'Ang bawat paksa ay naglalaman ng isang hanay ng mga card. Bagama''t suportado ang mga larawan at audio, opsyonal ang mga ito—ang nilalaman ay maaaring purong teksto o dynamic na binuo.'),
  ('tl', 'doc_study_modes_title', 'Mga Adaptive na Mode ng Pag-aaral'),
  ('tl', 'doc_study_modes_desc', 'Sinusuportahan ng Aliolo ang iba''t ibang mode ng pagsubok batay sa iyong nilalaman: Image-to-Text, Audio-to-Image, at Text-to-Audio. Tinitiyak ng multi-sensory na diskarte na ito na master mo ang mga paksa mula sa bawat anggulo.'),
  ('tl', 'doc_testing_title', 'Interactive na Pagsubok'),
  ('tl', 'doc_testing_desc', 'Hamunin ang iyong sarili sa mga multiple-choice question (MCQ). Awtomatikong magpapatuloy ang app habang sumasagot ka, na tumutulong sa iyong matuto nang mas mabilis.'),
  ('tl', 'doc_autoplay_title', 'Auto-Play na Pag-aaral'),
  ('tl', 'doc_autoplay_desc', 'Maaaring awtomatikong magpatuloy ang app sa susunod na card pagkatapos mong sumagot. Ang mga tamang sagot ay naghihintay ng 1s, habang ang mga maling sagot ay naghihintay ng 2s upang hayaan kang mag-review.'),
  ('tl', 'doc_math_title', 'Mga Paksa sa Matematika'),
  ('tl', 'doc_math_desc', 'Ang mga paksa sa matematika ay gumagamit ng mga espesyal na engine upang bumuo ng mga visualization ng card nang real-time. Nagtatampok ang mga paksang ito ng mga natatanging mode ng pag-aaral at pagsubok na iniayon sa mga partikular na konsepto sa matematika, na tinitiyak ang isang mas epektibong kapaligiran sa pagsasanay.'),
  ('tl', 'doc_organization_title', 'Pag-oorganisa ng Nilalaman'),
  ('tl', 'doc_organization_desc', 'Gamitin ang mga Folder upang pagpangkatin ang mga kaugnay na Paksa. Maaari ka ring gumawa ng mga Koleksyon upang i-organisa ang mga Paksa sa mga na-curate na landas.'),
  ('tl', 'doc_creation_title', 'Paggawa ng Mga Paksa at Card'),
  ('tl', 'doc_creation_desc', 'Gumawa ng sarili mong mga Paksa at magdagdag ng mga visual na Flashcard. Sinusuportahan ng bawat card ang isang imahe at isang opsyonal na audio file para sa pagbigkas.'),
  ('tl', 'doc_collections_purpose_title', 'Ang Layunin ng Mga Koleksyon'),
  ('tl', 'doc_collections_purpose_desc', 'Ang mga koleksyon ay mga na-curate na landas na nagpapangkat-pangkat sa mga Paksa. Kapag nagsimula ka ng isang sesyon mula sa isang Koleksyon, pinaghahalo ng system ang mga card mula sa lahat ng kasamang paksa upang magbigay ng randomized at komprehensibong pagsubok.'),
  ('tl', 'doc_card_scope_title', 'Kung Saan Nakatira ang Mga Card'),
  ('tl', 'doc_card_scope_desc', 'Ang mga card ay ang mga pangunahing bahagi ng pag-aaral at palaging kabilang sa isang partikular na Paksa. Bagama''t maaari mong i-organisa ang mga Paksa sa mga Folder o Koleksyon, ang mga card mismo ay dapat gawin sa loob ng isang Paksa.'),
  ('tl', 'doc_localization_ui_title', 'Pagdaragdag ng Mga Pagsasalin'),
  ('tl', 'doc_localization_ui_desc', 'Upang magdagdag ng naka-localize na data, i-tap lang ang icon ng language code (hal., EN, ES, FR) sa header ng editor. Binibigyang-daan ka nito na magbigay ng mga partikular na pangalan, paglalarawan, at nilalaman ng card para sa bawat suportadong wika. Ang tab na "Global" ay nagsisilbing pangunahing fallback kung walang ibinigay na partikular na pagsasalin.'),
  ('tl', 'doc_localization_details_title', 'Paano Gumagana ang Localization'),
  ('tl', 'doc_localization_details_desc', 'Ang wikang "Global" ay ang iyong pangunahing fallback—maaari itong maging anumang wika na pipiliin mo. Kung magbibigay ka ng mga partikular na pagsasalin (tulad ng Ingles o Espanyol), o-override ng mga ito ang Global na data kapag pinili lang ng isang user ang partikular na wika ng UI na iyon.'),
  ('tl', 'doc_json_title', 'JSON Localization'),
  ('tl', 'doc_json_desc', 'Ang mga advanced na creator ay maaaring gumamit ng JSON data upang magbigay ng mga naka-localize na pangalan at paglalarawan, na ginagawang accessible ang mga paksa sa lahat ng suportadong wika.'),
  ('tl', 'doc_media_title', 'Mga Limitasyon sa Pag-upload ng Media'),
  ('tl', 'doc_media_desc', 'Upang matiyak ang mabilis na pag-sync, panatilihing mababa sa 5MB ang mga larawan at mababa sa 10MB ang mga audio file.'),

  ('vi', 'doc_welcome_title', 'Chào mừng bạn đến với Aliolo'),
  ('vi', 'doc_welcome_desc', 'Aliolo là một nền tảng học tập trực quan được thiết kế để giúp bạn nắm vững các chủ đề thông qua flashcards và kiểm tra tương tác.'),
  ('vi', 'doc_pillars_title', '8 Trụ cột cốt lõi'),
  ('vi', 'doc_pillars_desc', 'Tất cả nội dung trong Aliolo được tổ chức thành 8 trụ cột nền tảng: Học thuật & Chuyên nghiệp, Thế giới, Tự nhiên, Cơ thể con người, Khoa học nhân văn, Giải trí, Kỹ thuật và Khác. Các danh mục này cung cấp một khung cấu trúc cho tất cả các chủ đề trên nền tảng.'),
  ('vi', 'doc_leaderboard_title', 'Bảng xếp hạng toàn cầu'),
  ('vi', 'doc_leaderboard_desc', 'Cạnh tranh với những người học trên toàn thế giới! Kiếm XP bằng cách hoàn thành các phiên học thẻ và thăng hạng. Vị trí của bạn được cập nhật theo thời gian thực khi bạn nắm vững các chủ đề mới.'),
  ('vi', 'doc_friends_title', 'Bạn bè & Lời mời'),
  ('vi', 'doc_friends_desc', 'Học tập sẽ tốt hơn khi có nhau! Mời bạn bè tham gia Aliolo thông qua hồ sơ của bạn. Các bạn có thể theo dõi tiến trình của nhau và duy trì động lực bằng cách xem ai duy trì được chuỗi ngày (streak) dài nhất.'),
  ('vi', 'doc_streaks_title', 'Hệ thống chuỗi ngày (Streak)'),
  ('vi', 'doc_streaks_desc', 'Sự kiên trì là chìa khóa! Hoàn thành mục tiêu hàng ngày của bạn mỗi ngày để xây dựng chuỗi ngày của bạn. Đừng bỏ lỡ một ngày nào, nếu không chuỗi ngày sẽ bị đặt lại.'),
  ('vi', 'doc_goals_title', 'Mục tiêu hàng ngày'),
  ('vi', 'doc_goals_desc', 'Thiết lập mục tiêu hoàn thành thẻ hàng ngày của bạn trong phần cài đặt. Các thay đổi đối với mục tiêu của bạn sẽ có hiệu lực bắt đầu từ ngày hôm sau.'),
  ('vi', 'doc_public_title', 'Công khai và Riêng tư'),
  ('vi', 'doc_public_desc', 'Các chủ đề có thể là riêng tư (chỉ bạn mới thấy) hoặc công khai. Nội dung công khai được chia sẻ với toàn bộ cộng đồng Aliolo, cho phép mọi người khám phá và học hỏi từ các sáng tạo của bạn.'),
  ('vi', 'doc_sync_title', 'Đồng bộ hóa đám mây'),
  ('vi', 'doc_sync_desc', 'Tiến trình của bạn được tự động đồng bộ hóa với đám mây. Bạn có thể chuyển đổi giữa phiên bản web và máy tính để bàn mà không bị mất chuỗi ngày của mình.'),
  ('vi', 'doc_feedback_title', 'Hệ thống phản hồi'),
  ('vi', 'doc_feedback_desc', 'Giúp chúng tôi cải thiện! Sử dụng biểu tượng phản hồi (Icons.feedback) trên bất kỳ Chủ đề hoặc Thư mục nào để báo cáo sự cố. Bạn cũng có thể gửi phản hồi chung về ứng dụng thông qua phần Hỗ trợ.'),
  ('vi', 'doc_lang_title', 'Ngôn ngữ học tập'),
  ('vi', 'doc_lang_desc', 'Luôn chọn ngôn ngữ học tập ưa thích của bạn ở menu trên cùng trước khi chọn một chủ đề. Điều này đảm bảo âm thanh và bản dịch chính xác được tải lên.'),
  ('vi', 'doc_filters_title', 'Tìm kiếm & Bộ lọc'),
  ('vi', 'doc_filters_desc', 'Tìm kiếm nội dung nhanh chóng bằng thanh tìm kiếm. Bạn có thể lọc theo Nhóm tuổi (Từ Nhỏ đến Nâng cao) hoặc thu hẹp chế độ xem của mình thành các Bộ sưu tập và Thư mục cụ thể.'),
  ('vi', 'doc_flashcards_title', 'Flashcards trực quan'),
  ('vi', 'doc_flashcards_desc', 'Mỗi chủ đề chứa một bộ thẻ. Mặc dù hình ảnh và âm thanh được hỗ trợ, nhưng chúng là tùy chọn—nội dung có thể thuần văn bản hoặc được tạo động.'),
  ('vi', 'doc_study_modes_title', 'Chế độ học tập thích ứng'),
  ('vi', 'doc_study_modes_desc', 'Aliolo hỗ trợ các chế độ kiểm tra khác nhau dựa trên nội dung của bạn: Hình ảnh sang Văn bản, Âm thanh sang Hình ảnh và Văn bản sang Âm thanh. Phương pháp đa giác quan này đảm bảo bạn nắm vững các chủ đề từ mọi góc độ.'),
  ('vi', 'doc_testing_title', 'Kiểm tra tương tác'),
  ('vi', 'doc_testing_desc', 'Thử thách bản thân với các câu hỏi trắc nghiệm (MCQ). Ứng dụng sẽ tự động chuyển tiếp khi bạn trả lời, giúp bạn học nhanh hơn.'),
  ('vi', 'doc_autoplay_title', 'Học tập tự động phát'),
  ('vi', 'doc_autoplay_desc', 'Ứng dụng có thể tự động chuyển sang thẻ tiếp theo sau khi bạn trả lời. Câu trả lời đúng đợi 1 giây, trong khi câu trả lời sai đợi 2 giây để bạn xem lại.'),
  ('vi', 'doc_math_title', 'Các chủ đề toán học'),
  ('vi', 'doc_math_desc', 'Các chủ đề toán học sử dụng các công cụ chuyên dụng để tạo trực quan hóa thẻ theo thời gian thực. Các chủ đề này có các chế độ học tập và kiểm tra độc đáo được điều chỉnh cho các khái niệm toán học cụ thể, đảm bảo môi trường thực hành hiệu quả hơn.'),
  ('vi', 'doc_organization_title', 'Tổ chức nội dung'),
  ('vi', 'doc_organization_desc', 'Sử dụng Thư mục để nhóm các Chủ đề liên quan lại với nhau. Bạn cũng có thể tạo Bộ sưu tập để sắp xếp các Chủ đề thành các lộ trình được tuyển chọn.'),
  ('vi', 'doc_creation_title', 'Tạo chủ đề & thẻ'),
  ('vi', 'doc_creation_desc', 'Tạo Chủ đề của riêng bạn và thêm Flashcards trực quan. Mỗi thẻ hỗ trợ một hình ảnh và một tệp âm thanh tùy chọn để phát âm.'),
  ('vi', 'doc_collections_purpose_title', 'Mục đích của Bộ sưu tập'),
  ('vi', 'doc_collections_purpose_desc', 'Bộ sưu tập là các lộ trình được tuyển chọn nhóm các Chủ đề lại với nhau. Khi bạn bắt đầu một phiên học từ một Bộ sưu tập, hệ thống sẽ trộn các thẻ từ tất cả các chủ đề bao gồm để cung cấp một bài kiểm tra toàn diện, ngẫu nhiên.'),
  ('vi', 'doc_card_scope_title', 'Vị trí của thẻ'),
  ('vi', 'doc_card_scope_desc', 'Thẻ là các khối xây dựng của việc học và luôn thuộc về một Chủ đề cụ thể. Mặc dù bạn có thể sắp xếp các Chủ đề vào Thư mục hoặc Bộ sưu tập, nhưng bản thân các thẻ phải được tạo trong một Chủ đề.'),
  ('vi', 'doc_localization_ui_title', 'Thêm bản dịch'),
  ('vi', 'doc_localization_ui_desc', 'Để thêm dữ liệu được bản địa hóa, chỉ cần chạm vào biểu tượng mã ngôn ngữ (ví dụ: EN, ES, FR) trong tiêu đề trình chỉnh sửa. Điều này cho phép bạn cung cấp tên, mô tả và nội dung thẻ cụ thể cho từng ngôn ngữ được hỗ trợ. Tab "Toàn cầu" đóng vai trò là phương án dự phòng chính nếu không có bản dịch cụ thể nào được cung cấp.'),
  ('vi', 'doc_localization_details_title', 'Cách thức bản địa hóa hoạt động'),
  ('vi', 'doc_localization_details_desc', 'Ngôn ngữ "Toàn cầu" là phương án dự phòng chính của bạn—đó có thể là bất kỳ ngôn ngữ nào bạn chọn. Nếu bạn cung cấp các bản dịch cụ thể (như tiếng Anh hoặc tiếng Tây Ban Nha), chúng sẽ chỉ ghi đè dữ liệu Toàn cầu khi người dùng chọn ngôn ngữ giao diện người dùng cụ thể đó.'),
  ('vi', 'doc_json_title', 'Bản địa hóa JSON'),
  ('vi', 'doc_json_desc', 'Các nhà sáng tạo nâng cao có thể sử dụng dữ liệu JSON để cung cấp tên và mô tả được bản địa hóa, giúp các chủ đề có thể tiếp cận được trên tất cả các ngôn ngữ được hỗ trợ.'),
  ('vi', 'doc_media_title', 'Giới hạn tải lên phương tiện'),
  ('vi', 'doc_media_desc', 'Để đảm bảo đồng bộ hóa nhanh chóng, hãy để hình ảnh dưới 5MB và tệp âm thanh dưới 10MB.'),

  ('tr', 'doc_welcome_title', 'Aliolo''ya Hoş Geldiniz'),
  ('tr', 'doc_welcome_desc', 'Aliolo, flashcardlar ve etkileşimli testler aracılığıyla konulara hakim olmanıza yardımcı olmak için tasarlanmış görsel bir öğrenme platformudur.'),
  ('tr', 'doc_pillars_title', '8 Temel Sütun'),
  ('tr', 'doc_pillars_desc', 'Aliolo''daki tüm içerik 8 temel sütun halinde düzenlenmiştir: Akademik ve Profesyonel, Dünya, Doğa, İnsan Vücudu, Beşeri Bilimler, Eğlence, Mühendislik ve Diğer. Bu kategoriler, platformdaki tüm konular için yapılandırılmış bir çerçeve sağlar.'),
  ('tr', 'doc_leaderboard_title', 'Küresel Liderlik Tablosu'),
  ('tr', 'doc_leaderboard_desc', 'Dünya çapındaki öğrenicilerle yarışın! Kart oturumlarını tamamlayarak XP kazanın ve sıralamada yükselin. Yeni konularda ustalaştıkça konumunuz gerçek zamanlı olarak güncellenir.'),
  ('tr', 'doc_friends_title', 'Arkadaşlar ve Davetler'),
  ('tr', 'doc_friends_desc', 'Birlikte öğrenmek daha iyidir! Profiliniz aracılığıyla arkadaşlarınızı Aliolo''ya davet edin. Birbirinizin ilerlemesini takip edebilir ve en uzun seriyi kimin koruduğunu görerek motivasyonunuzu koruyabilirsiniz.'),
  ('tr', 'doc_streaks_title', 'Seri (Streak) Sistemi'),
  ('tr', 'doc_streaks_desc', 'İstikrar anahtardır! Serinizi oluşturmak için her gün günlük hedefinizi tamamlayın. Bir günü bile kaçırmayın, aksi takdirde seri sıfırlanır.'),
  ('tr', 'doc_goals_title', 'Günlük Hedefler'),
  ('tr', 'doc_goals_desc', 'Ayarlardan günlük kart tamamlama hedefinizi belirleyin. Hedefinizdeki değişiklikler ertesi günden itibaren geçerli olur.'),
  ('tr', 'doc_public_title', 'Genel ve Özel'),
  ('tr', 'doc_public_desc', 'Konular özel (yalnızca sizin tarafınızdan görülebilir) veya genel olabilir. Genel içerik tüm Aliolo topluluğuyla paylaşılır ve herkesin kreasyonlarınızı keşfetmesine ve onlardan öğrenmesine olanak tanır.'),
  ('tr', 'doc_sync_title', 'Bulut Senkronizasyonu'),
  ('tr', 'doc_sync_desc', 'İlerlemeniz otomatik olarak bulutla senkronize edilir. Serinizi kaybetmeden web ve masaüstü sürümleri arasında geçiş yapabilirsiniz.'),
  ('tr', 'doc_feedback_title', 'Geri Bildirim Sistemi'),
  ('tr', 'doc_feedback_desc', 'Gelişmemize yardımcı olun! Sorunları bildirmek için herhangi bir Konu veya Klasör üzerindeki geri bildirim simgesini (Icons.feedback) kullanın. Destek bölümü aracılığıyla genel uygulama geri bildirimi de gönderebilirsiniz.'),
  ('tr', 'doc_lang_title', 'Öğrenme Dili'),
  ('tr', 'doc_lang_desc', 'Bir konu seçmeden önce daima üst menüden tercih ettiğiniz öğrenme dilini seçin. Bu, doğru ses ve çevirilerin yüklenmesini sağlar.'),
  ('tr', 'doc_filters_title', 'Arama ve Filtreler'),
  ('tr', 'doc_filters_desc', 'Arama çubuğunu kullanarak içeriği hızla bulun. Yaş Grubuna göre (Erken''den Gelişmiş''e) filtreleyebilir veya görünümünüzü belirli Koleksiyonlar ve Klasörlerle daraltabilirsiniz.'),
  ('tr', 'doc_flashcards_title', 'Görsel Flashcardlar'),
  ('tr', 'doc_flashcards_desc', 'Her konu bir dizi kart içerir. Resimler ve ses desteklense de isteğe bağlıdır; içerik tamamen metinsel olabilir veya dinamik olarak oluşturulabilir.'),
  ('tr', 'doc_study_modes_title', 'Uyarlanabilir Çalışma Modları'),
  ('tr', 'doc_study_modes_desc', 'Aliolo, içeriğinize göre çeşitli test modlarını destekler: Resimden Metne, Sesten Resme ve Metinden Sese. Bu çok duyulu yaklaşım, konulara her açıdan hakim olmanızı sağlar.'),
  ('tr', 'doc_testing_title', 'Etkileşimli Test'),
  ('tr', 'doc_testing_desc', 'Çoktan seçmeli sorularla (MCQ) kendinize meydan okuyun. Uygulama, siz cevapladıkça otomatik olarak ilerleyerek daha hızlı öğrenmenize yardımcı olur.'),
  ('tr', 'doc_autoplay_title', 'Otomatik Oynatma ile Öğrenme'),
  ('tr', 'doc_autoplay_desc', 'Uygulama, siz cevapladıktan sonra otomatik olarak bir sonraki karta geçebilir. Doğru cevaplar 1 saniye beklerken, yanlış cevaplar incelemeniz için 2 saniye bekler.'),
  ('tr', 'doc_math_title', 'Matematik Konuları'),
  ('tr', 'doc_math_desc', 'Matematik konuları, gerçek zamanlı olarak kart görselleştirmeleri oluşturmak için özel motorlar kullanır. Bu konular, belirli matematiksel kavramlara göre uyarlanmış benzersiz öğrenme ve test modlarına sahiptir ve daha etkili bir uygulama ortamı sağlar.'),
  ('tr', 'doc_organization_title', 'İçeriği Düzenleme'),
  ('tr', 'doc_organization_desc', 'İlgili Konuları bir araya getirmek için Klasörleri kullanın. Konuları küratörlü yollar halinde düzenlemek için Koleksiyonlar da oluşturabilirsiniz.'),
  ('tr', 'doc_creation_title', 'Konu ve Kart Oluşturma'),
  ('tr', 'doc_creation_desc', ' Kendi Konularınızı oluşturun ve görsel Flashcardlar ekleyin. Her kart, telaffuz için bir resmi ve isteğe bağlı bir ses dosyasını destekler.'),
  ('tr', 'doc_collections_purpose_title', 'Koleksiyonların Amacı'),
  ('tr', 'doc_collections_purpose_desc', 'Koleksiyonlar, Konuları bir araya getiren küratörlü yollardır. Bir Koleksiyondan bir oturum başlattığınızda, sistem rastgele ve kapsamlı bir test sağlamak için dahil edilen tüm konulardan kartları karıştırır.'),
  ('tr', 'doc_card_scope_title', 'Kartların Yeri'),
  ('tr', 'doc_card_scope_desc', 'Kartlar öğrenmenin yapı taşlarıdır ve her zaman belirli bir Konuya aittir. Konuları Klasörler veya Koleksiyonlar halinde düzenleyebilseniz de, kartların kendileri bir Konu içinde oluşturulmalıdır.'),
  ('tr', 'doc_localization_ui_title', 'Çeviri Ekleme'),
  ('tr', 'doc_localization_ui_desc', 'Yerelleştirilmiş veriler eklemek için düzenleyici başlığındaki dil kodu simgesine (örneğin EN, ES, FR) dokunmanız yeterlidir. Bu, desteklenen her dil için belirli adlar, açıklamalar ve kart içeriği sağlamanıza olanak tanır. Belirli bir çeviri sağlanmazsa "Global" sekmesi birincil geri dönüş işlevi görür.'),
  ('tr', 'doc_localization_details_title', 'Yerelleştirme Nasıl Çalışır?'),
  ('tr', 'doc_localization_details_desc', '"Global" dil, birincil geri dönüşünüzdür; seçtiğiniz herhangi bir dil olabilir. Belirli çeviriler (İngilizce veya İspanyolca gibi) sağlarsanız, bunlar Global verileri yalnızca bir kullanıcı o belirli kullanıcı arayüzü dilini seçtiğinde geçersiz kılar.'),
  ('tr', 'doc_json_title', 'JSON Yerelleştirme'),
  ('tr', 'doc_json_desc', 'Gelişmiş oluşturucular, yerelleştirilmiş adlar ve açıklamalar sağlamak için JSON verilerini kullanabilir ve konuları desteklenen tüm dillerde erişilebilir hale getirebilir.'),
  ('tr', 'doc_media_title', 'Medya Yükleme Limitleri'),
  ('tr', 'doc_media_desc', 'Hızlı senkronizasyon sağlamak için resimleri 5 MB''ın, ses dosyalarını ise 10 MB''ın altında tutun.'),
